export function ShoppableFeedClient({ initialProducts }: ShoppableFeedClientProps) {
  const [activeVideoIndex, setActiveVideoIndex] = useState(0);

  // Simple scroll snap handling to track active video
  useEffect(() => {
    const handleScroll = () => {
      const container = document.getElementById("feed-container");
      if (!container) return;

      const index = Math.round(container.scrollTop / window.innerHeight);
      if (index !== activeVideoIndex) {
        setActiveVideoIndex(index);
      }
    };

    const container = document.getElementById("feed-container");
    container?.addEventListener("scroll", handleScroll);
    return () => container?.removeEventListener("scroll", handleScroll);
  }, [activeVideoIndex]);

  return (
    <div
      id="feed-container"
      className="h-screen w-full overflow-y-scroll snap-y snap-mandatory scroll-smooth relative"
    >
      {initialProducts.map((product, index) => (
        <FeedItem
          key={product.id}
          product={product}
          isActive={index === activeVideoIndex}
        />
      ))}
    </div>
  );
}

