"use client";

import { useState, Suspense } from "react";
import { useRouter, usePathname, useSearchParams } from "next/navigation";
import { SlidersHorizontal, ChevronDown, Check } from "lucide-react";
import { useDebounce } from "@/hooks/use-debounce";

interface Category {
  id: string;
  name: string;
}

interface Store {
  id: string;
  name: string;
}

interface SearchClientProps {
  initialQuery?: string;
  initialCategoryId?: string;
  initialStoreId?: string;
  initialMinPrice?: number;
  initialMaxPrice?: number;
  categories: Category[];
  stores: Store[];
}

function SearchClientContent({
  initialQuery = "",
  initialCategoryId,
  initialStoreId,
  initialMinPrice,
  initialMaxPrice,
  categories,
  stores,
}: SearchClientProps) {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();

  const [query, setQuery] = useState(initialQuery);
  const [minPrice, setMinPrice] = useState(initialMinPrice?.toString() || "");
  const [maxPrice, setMaxPrice] = useState(initialMaxPrice?.toString() || "");
  const [isFiltersOpen, setIsFiltersOpen] = useState(false);

  const debouncedQuery = useDebounce(query, 500);
  const debouncedMinPrice = useDebounce(minPrice, 500);
  const debouncedMaxPrice = useDebounce(maxPrice, 500);

  // Trigger update when debounced values change
  // Note: We avoid running this on initial mount to prevent unnecessary pushes
  const updateUrl = (
    newQuery: string,
    newMin: string,
    newMax: string,
    newCategoryId: string | undefined,
    newStoreId: string | undefined
  ) => {
    const params = new URLSearchParams(searchParams);

    if (newQuery) params.set("q", newQuery);
    else params.delete("q");

    if (newMin) params.set("minPrice", newMin);
    else params.delete("minPrice");

    if (newMax) params.set("maxPrice", newMax);
    else params.delete("maxPrice");

    if (newCategoryId) params.set("categoryId", newCategoryId);
    else params.delete("categoryId");

    if (newStoreId) params.set("storeId", newStoreId);
    else params.delete("storeId");

    params.delete("page"); // Reset page on filter change

    router.push(`${pathname}?${params.toString()}`);
  };

  const handleCategorySelect = (categoryId: string) => {
    const newCat = initialCategoryId === categoryId ? undefined : categoryId;
    updateUrl(query, minPrice, maxPrice, newCat, initialStoreId);
  };

  const handleStoreSelect = (storeId: string) => {
    const newStore = initialStoreId === storeId ? undefined : storeId;
    updateUrl(query, minPrice, maxPrice, initialCategoryId, newStore);
  };

  const handlePriceApply = () => {
    updateUrl(query, minPrice, maxPrice, initialCategoryId, initialStoreId);
  };

  const handleQueryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);
  };

  const handleQueryKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      updateUrl(query, minPrice, maxPrice, initialCategoryId, initialStoreId);
    }
  };

  const handleClearFilters = () => {
    setQuery("");
    setMinPrice("");
    setMaxPrice("");
    router.push(pathname);
  };

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden sticky top-28">
      {/* Mobile Toggle */}
      <div className="lg:hidden p-4 border-b border-gray-100">
        <button
          onClick={() => setIsFiltersOpen(!isFiltersOpen)}
          className="flex items-center justify-between w-full font-medium text-gray-900"
        >
          <span className="flex items-center gap-2">
            <SlidersHorizontal className="w-5 h-5" />
            Фильтры
          </span>
          <ChevronDown
            className={`w-5 h-5 transition-transform ${
              isFiltersOpen ? "rotate-180" : ""
            }`}
          />
        </button>
      </div>

      <div className={`p-5 ${isFiltersOpen ? "block" : "hidden lg:block"} space-y-8`}>
        {/* Header with clear button */}
        <div className="flex items-center justify-between pb-4 border-b border-gray-100">
          <h2 className="font-semibold text-gray-900 flex items-center gap-2">
            <SlidersHorizontal className="w-4 h-4" />
            Фильтры
          </h2>
          {(initialQuery ||
            initialCategoryId ||
            initialStoreId ||
            initialMinPrice ||
            initialMaxPrice) && (
            <button
              onClick={handleClearFilters}
              className="text-sm text-blue-600 hover:text-blue-700 font-medium transition-colors"
            >
              Сбросить
            </button>
          )}
        </div>

        {/* Search Input */}
        <div className="space-y-3">
          <h3 className="text-sm font-medium text-gray-900 uppercase tracking-wider">
            Поиск
          </h3>
          <input
            type="text"
            value={query}
            onChange={handleQueryChange}
            onKeyDown={handleQueryKeyDown}
            placeholder="Название товара..."
            className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:bg-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
          />
        </div>

        {/* Price Filter */}
        <div className="space-y-3">
          <h3 className="text-sm font-medium text-gray-900 uppercase tracking-wider">
            Цена, $
          </h3>
          <div className="flex items-center gap-2">
            <input
              type="number"
              placeholder="От"
              value={minPrice}
              onChange={(e) => setMinPrice(e.target.value)}
              className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:bg-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
            />
            <span className="text-gray-400">-</span>
            <input
              type="number"
              placeholder="До"
              value={maxPrice}
              onChange={(e) => setMaxPrice(e.target.value)}
              className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:bg-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
            />
          </div>
          <button
            onClick={handlePriceApply}
            className="w-full py-2 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-lg text-sm font-medium transition-colors"
          >
            Применить
          </button>
        </div>

        {/* Categories */}
        {categories.length > 0 && (
          <div className="space-y-3">
            <h3 className="text-sm font-medium text-gray-900 uppercase tracking-wider">
              Категории
            </h3>
            <div className="space-y-2 max-h-48 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-gray-200 scrollbar-track-transparent">
              {categories.map((category) => {
                const isSelected = initialCategoryId === category.id;
                return (
                  <button
                    key={category.id}
                    onClick={() => handleCategorySelect(category.id)}
                    className={`flex items-center justify-between w-full px-3 py-2 rounded-lg text-sm transition-colors text-left ${
                      isSelected
                        ? "bg-blue-50 text-blue-700 font-medium"
                        : "text-gray-600 hover:bg-gray-50 hover:text-gray-900"
                    }`}
                  >
                    <span className="truncate pr-2">{category.name}</span>
                    {isSelected && <Check className="w-4 h-4 text-blue-600 flex-shrink-0" />}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* Stores */}
        {stores.length > 0 && (
          <div className="space-y-3">
            <h3 className="text-sm font-medium text-gray-900 uppercase tracking-wider">
              Магазины
            </h3>
            <div className="space-y-2 max-h-48 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-gray-200 scrollbar-track-transparent">
              {stores.map((store) => {
                const isSelected = initialStoreId === store.id;
                return (
                  <button
                    key={store.id}
                    onClick={() => handleStoreSelect(store.id)}
                    className={`flex items-center justify-between w-full px-3 py-2 rounded-lg text-sm transition-colors text-left ${
                      isSelected
                        ? "bg-blue-50 text-blue-700 font-medium"
                        : "text-gray-600 hover:bg-gray-50 hover:text-gray-900"
                    }`}
                  >
                    <span className="truncate pr-2">{store.name}</span>
                    {isSelected && <Check className="w-4 h-4 text-blue-600 flex-shrink-0" />}
                  </button>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

