"use client";

import { useState } from "react";
import { OrderButton } from "@/components/renderers/order-button";
import { WishlistButton } from "@/components/ui/wishlist-button";

interface TierPrice {
  minQuantity: number;
  price: number;
}

interface EffectivePrice {
  price: number;
  groupName?: string;
  discountType?: string;
}

interface ProductOptionsProps {
  product: {
    id: string;
    storeId: string;
    price: number;
    stock: number;
    attributes?: { name: string; values: string[] }[];
    variants?: { id?: string; price?: number; stock: number; options?: Record<string, string> }[];
  };
  isWished: boolean;
  tierPrices?: TierPrice[];
  effectivePrice?: EffectivePrice;
}

export const ProductOptions = ({ product, isWished, tierPrices = [], effectivePrice }: ProductOptionsProps) => {
  const [selectedAttributes, setSelectedAttributes] = useState<Record<string, string>>({});
  const [selectedVariantId, setSelectedVariantId] = useState<string | undefined>();

  const attributes = Array.isArray(product.attributes) ? product.attributes : [];
  const variants = Array.isArray(product.variants) ? product.variants : [];

  const handleAttributeSelect = (name: string, value: string) => {
    setSelectedAttributes((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const selectedVariant = variants.find((variant) => {
    if (!variant.options) return false;
    return Object.entries(selectedAttributes).every(
      ([key, value]) => variant.options?.[key] === value
    );
  });

  const basePrice = selectedVariant?.price ?? product.price;
  const displayStock = selectedVariant?.stock ?? product.stock;

  // Використовуємо effectivePrice якщо доступно, інакше basePrice
  const displayPrice = effectivePrice ? effectivePrice.price : basePrice;
  // Перевіряємо, чи дійсно є знижка (ефективна ціна менша за базову)
  const hasDiscount = effectivePrice && effectivePrice.price < basePrice && effectivePrice.price !== basePrice;
  const discountAmount = hasDiscount ? basePrice - effectivePrice.price : 0;
  const discountPercentage = hasDiscount ? Math.round((discountAmount / basePrice) * 100) : 0;

  return (
    <div className="mt-8">
      {/* Ціна з відображенням знижки */}
      <div className="flex items-center gap-3">
        {hasDiscount && (
          <>
            <span className="text-2xl text-gray-400 line-through">${basePrice.toFixed(2)}</span>
            <span className="bg-green-100 text-green-800 px-2 py-1 rounded text-sm font-medium">
              -{discountPercentage}%
            </span>
          </>
        )}
        <p className="text-3xl text-gray-900">${displayPrice.toFixed(2)}</p>
      </div>

      {/* Відображення назви групи клієнтів */}
      {effectivePrice?.groupName && (
        <p className="mt-1 text-sm text-gray-500">
          Ціна для групи: <span className="font-medium text-gray-700">{effectivePrice.groupName}</span>
        </p>
      )}

      {/* Tier Prices Table */}
      {tierPrices && tierPrices.length > 0 && (
        <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200">
          <h4 className="text-sm font-medium text-gray-700 mb-2">Ціна залежить від кількості:</h4>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 text-sm">
            {tierPrices.map((tier, idx) => (
              <div key={idx} className="flex flex-col bg-white rounded px-3 py-2 border border-gray-200">
                <span className="text-gray-500 text-xs">від {tier.minQuantity} шт.</span>
                <span className="font-semibold text-gray-900">${tier.price.toFixed(2)}/од</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {attributes.length > 0 && (
        <div className="mt-6 space-y-4">
          {attributes.map((attr, idx) => (
            <div key={idx}>
              <h3 className="text-sm font-medium text-gray-900">{attr.name}</h3>
              <div className="mt-2 flex flex-wrap gap-2">
                {attr.values.map((value: string) => {
                  const isSelected = selectedAttributes[attr.name] === value;
                  return (
                    <button
                      key={value}
                      onClick={() => {
                        handleAttributeSelect(attr.name, value);
                        // Знаходимо варіант після вибору атрибуту
                        const newSelected = { ...selectedAttributes, [attr.name]: value };
                        const foundVariant = variants.find((v) => {
                          if (!v.options) return false;
                          return Object.entries(newSelected).every(
                            ([key, val]) => v.options?.[key] === val
                          );
                        });
                        if (foundVariant?.id) {
                          setSelectedVariantId(foundVariant.id);
                        }
                      }}
                      className={`px-3 py-1 text-sm border rounded-md transition-colors ${
                        isSelected
                          ? "bg-gray-900 text-white border-gray-900"
                          : "bg-white text-gray-900 border-gray-300 hover:border-gray-900"
                      }`}
                    >
                      {value}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Відображення stock обраної варіації */}
      {selectedVariant ? (
        selectedVariant.stock > 0 ? (
          <p className="mt-4 text-sm text-green-600">
            Наявно: {selectedVariant.stock} шт.
          </p>
        ) : (
          <p className="mt-4 text-sm text-red-600">Немає в наявності</p>
        )
      ) : displayStock > 0 ? (
        <p className="mt-4 text-sm text-green-600">Наявно: {displayStock} шт.</p>
      ) : (
        <p className="mt-4 text-sm text-red-600">Немає в наявності</p>
      )}

      <div className="mt-10 flex items-center gap-4">
        <OrderButton
          storeId={product.storeId}
          productId={product.id}
          variantId={selectedVariant?.id}
        />
        <WishlistButton productId={product.id} isWished={isWished} />
      </div>
    </div>
  );
};

import { prisma } from "@/lib/prisma";
