import { getProductBreadcrumb } from "@/lib/breadcrumb";
import { getEffectivePrice } from "@/actions/customer-groups";

interface ProductPageProps {
  params: Promise<{
    storeSlug: string;
    productId: string;
  }>;
}

// Отримання locale з cookies
async function getLocale() {
  const cookieStore = await cookies();
  return cookieStore.get("NEXT_LOCALE")?.value || "uk";
}

export async function generateMetadata({ params }: ProductPageProps): Promise<Metadata> {
  const { productId } = await params;
  const locale = await getLocale();

  const product = await prisma.product.findUnique({
    where: { id: productId },
    include: {
      store: true,
    },
  });

  if (!product) {
    return {
      title: "Товар не знайдено",
      description: "Сторінка товару не знайдена.",
    };
  }

  // Отримуємо переклад для поточної мови
  const translation = await prisma.productTranslation.findUnique({
    where: {
      productId_locale: {
        productId,
        locale: locale as any,
      },
    },
  });

  const displayName = translation?.name || product.name;
  const displayDescription = translation?.description || product.description || "";
  const displaySeoTitle = translation?.seoTitle || product.seoTitle;
  const displaySeoDescription = translation?.seoDescription || "";

  const title = `${displaySeoTitle || displayName} | ${product.store?.name || "Маркетплейс"}`;
  const description = displaySeoDescription || displayDescription || `Купіть ${displayName} в магазині ${product.store?.name || "Маркетплейс"}.`;

  return {
    title,
    description,
    openGraph: {
      title,
      description,
      images: product.imageUrl ? [product.imageUrl] : [],
    },
  };
}

export default async function ProductPage(props: ProductPageProps) {
  const params = await props.params;
  const { storeSlug, productId } = params;
  const session = await auth();
  const locale = await getLocale();

  const product = await prisma.product.findUnique({
    where: { id: productId },
    include: {
      store: true,
      reviews: {
        include: {
          user: {
            select: {
              name: true,
              image: true,
            },
          },
        },
        orderBy: {
          createdAt: "desc",
        },
      },
      wishlists: session?.user?.id
        ? {
            where: {
              userId: session.user.id,
            },
            select: { id: true },
          }
        : false,
      tierPrices: {
        orderBy: { minQuantity: 'asc' },
      },
    },
  });

  if (!product || product.store.slug !== storeSlug) {
    return notFound();
  }

  // Отримуємо переклад для поточної мови
  const translation = await prisma.productTranslation.findUnique({
    where: {
      productId_locale: {
        productId,
        locale: locale as any,
      },
    },
  });

  // Використовуємо перекладені значення або базові
  const displayName = translation?.name || product.name;
  const displayDescription = translation?.description || product.description;
  const displaySeoTitle = translation?.seoTitle || product.seoTitle;
  const displaySeoDescription = translation?.seoDescription || product.seoDescription;

  const averageRating =
    product.reviews.length > 0
      ? product.reviews.reduce((acc: number, r) => acc + r.rating, 0) / product.reviews.length
      : 0;

  const isWished = product.wishlists && product.wishlists.length > 0;

  const relatedProducts = await getRelatedProducts(product.id, product.storeId, 4);

  // Отримуємо ефективну ціну для користувача
  const effectivePriceResult = await getEffectivePrice(
    product.id,
    session?.user?.id || null,
    product.price
  );

  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "Product",
    name: displayName,
    description: displayDescription || undefined,
    image: product.imageUrl || undefined,
    sku: product.id,
    offers: {
      "@type": "Offer",
      priceCurrency: "UAH",
      price: Number(product.price),
      availability:
        product.stock > 0
          ? "https://schema.org/InStock"
          : "https://schema.org/OutOfStock",
      url: `${
        process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000"
      }/${storeSlug}/product/${productId}`,
    },
    ...(averageRating > 0 && {
      aggregateRating: {
        "@type": "AggregateRating",
        ratingValue: averageRating.toFixed(1),
        reviewCount: product.reviews.length,
      },
    }),
  };

  // Отримуємо breadcrumb
  const breadcrumbItems = await getProductBreadcrumb(productId, storeSlug);

  // JSON-LD для breadcrumb
  const breadcrumbJsonLd = {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    itemListElement: [
      {
        "@type": "ListItem",
        position: 1,
        name: "Головна",
        item: `${process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000"}/${storeSlug}`,
      },
      ...breadcrumbItems.map((item, index) => ({
        "@type": "ListItem" as const,
        position: index + 2,
        name: item.label,
        item: item.href
          ? `${process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000"}${item.href}`
          : undefined,
      })),
    ],
  };

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
      />
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <Breadcrumb items={breadcrumbItems} storeSlug={storeSlug} />
        <div className="lg:grid lg:grid-cols-2 lg:gap-x-8 lg:items-start">
          {/* Image gallery */}
          <div className="flex flex-col">
            <div className="w-full aspect-w-1 aspect-h-1 bg-gray-200 rounded-lg overflow-hidden">
              {product.imageUrl ? (
                <Image
                  src={product.imageUrl}
                  alt={displayName}
                  className="w-full h-full object-center object-cover"
                  width={500}
                  height={500}
                  placeholder="blur"
                  blurDataURL="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII="
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-gray-400">
                  No image
                </div>
              )}
            </div>
          </div>

          {/* Product info */}
          <div className="mt-10 px-4 sm:px-0 sm:mt-16 lg:mt-0">
            <h1 className="text-3xl font-extrabold tracking-tight text-gray-900">
              {displayName}
