import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";
import { redirect, notFound } from "next/navigation";
import { getOrderReturnRequests } from "@/actions/returns";
import { ReturnRequestClient } from "./client";
import type { Prisma } from "@prisma/client";

interface ReturnPageProps {
  params: Promise<{ orderId: string }>;
}

type OrderWithItems = Prisma.OrderGetPayload<{
  include: {
    store: true;
    orderItems: {
      include: {
        product: {
          select: {
            id: true;
            name: true;
            imageUrl: true;
          };
        };
      };
    };
  };
}>;

export default async function ReturnRequestPage({ params }: ReturnPageProps) {
  const { orderId } = await params;
  const session = await auth();

  if (!session?.user) {
    redirect("/login");
  }

  // Получаем заказ с товарами
  const order = (await prisma.order.findFirst({
    where: {
      id: orderId,
      customerEmail: session.user.email!,
    },
    include: {
      store: true,
      orderItems: {
        include: {
          product: {
            select: {
              id: true,
              name: true,
              imageUrl: true,
            },
          },
        },
      },
    },
  })) as OrderWithItems | null;

  if (!order) {
    notFound();
  }

  // Проверяем, что заказ доставлен или завершён
  const returnableStatuses = ["COMPLETED", "SHIPPED"];
  if (!returnableStatuses.includes(order.status)) {
    redirect(`/account`);
  }

  // Проверяем 14-дневный лимит
  const daysSinceOrder =
    (Date.now() - new Date(order.createdAt).getTime()) /
    (1000 * 60 * 60 * 24);
  if (daysSinceOrder > 14) {
    redirect(`/account`);
  }

  // Проверяем, нет ли уже активного возврата
  const existingReturns = await getOrderReturnRequests(orderId);
  const activeReturn = existingReturns.find(
    (r) => r.status !== "REJECTED"
  );

  return (
    <ReturnRequestClient
      order={order}
      existingReturn={activeReturn ?? null}
    />
  );
}

