import { NextRequest } from "next/server";
import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";
import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const isMockMode = !process.env.OPENAI_API_KEY;

// Промпти для різних типів генерації
const PROMPTS = {
  "product-description": (context: string, tone: string) => ({
    system: `Ти професійний AI-копірайтер для інтернет-магазинів.
Напиши продаючий опис товару на основі наданого запиту.
Тон: ${tone}.
Опис має бути привабливим, структурованим та готовим до публікації.
Використовуй HTML-теги для структурування (h2, p, ul, li) де доречно.`,
    user: context,
  }),

  "seo-meta": (title: string, content: string) => ({
    system: `Ти SEO-спеціаліст. На основі назви та опису товару згенеруй:
1. Meta Title (до 60 символів, продаючий)
2. Meta Description (до 160 символів, із закликом до дії)
3. Ключові слова (через непої)

Поверни результат СТРОГО в форматі JSON без markdown форматування:
{"seoTitle": "...", "seoDescription": "...", "tags": "..."}`,
    user: `Назва: ${title}\nОпис: ${content}`,
  }),

  "rewrite": (text: string, mode: string) => {
    const modeInstructions: Record<string, string> = {
      professional: "Зроби текст більш професійним та діловим.",
      friendly: "Зроби текст більш дружнім та невимушеним.",
      concise: "Зроби текст більш стислим та лаконічним.",
      detailed: "Розшир текст, додай більше деталей та пояснень.",
    };
    return {
      system: `Ти професійний редактор-копірайтер.
Твоє завдання — переписати наданий текст, дотримуючись інструкції.
Інструкція: ${modeInstructions[mode] || modeInstructions.professional}
Збережи HTML-розмітку, якщо вона є.`,
      user: `Вихідний текст: ${text}`,
    };
  },
};

export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return Response.json({ success: false, error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();
    const { type, context, storeId, tone, title, mode } = body;

    if (!storeId) {
      return Response.json({ success: false, error: "Store ID is required" }, { status: 400 });
    }

    // Перевірка доступ до магазину
    const store = await prisma.store.findFirst({
      where: { id: storeId, ownerId: session.user.id },
    });

    if (!store) {
      return Response.json({ success: false, error: "Store not found or no access" }, { status: 403 });
    }

    // Лічильник генерацій
    await prisma.user.update({
      where: { id: session.user.id },
      data: { aiGenerationsCount: { increment: 1 } },
    });

    // Mock mode для розробки без API ключа
    if (isMockMode) {
      await new Promise((resolve) => setTimeout(resolve, 1000));

      if (type === "product-description") {
        return Response.json({
          success: true,
          text: `[MOCK AI] Опис товару на основі: "${context}". Тон: ${tone || "Профессиональный"}.\n\nЦей товар відрізняється високою якістю та надійністю. Замовляйте просто зараз!`,
        });
      }

      if (type === "seo-meta") {
        return Response.json({
          success: true,
          data: {
            seoTitle: `${title || "Товар"} | Купити за кращою ціною | Наш магазин`,
            seoDescription: `Замовляйте ${title || "товар"} просто зараз! Чудова якість та швидка доставка.`,
            tags: `${title || "товар"}, купити, ціна, відгуки`,
          },
        });
      }

      if (type === "rewrite") {
        return Response.json({
          success: true,
          text: `[MOCK AI] Переписано (${mode || "professional"}): ${context?.substring(0, 100)}...`,
        });
      }
    }

    let result;

    // Обробка різних типів запитів
    if (type === "product-description") {
      const { system, user } = PROMPTS["product-description"](context || "", tone || "Профессиональный");
      const { text } = await generateText({
        model: openai("gpt-4o-mini"),
        system,
        prompt: user,
      });
      result = { success: true, text };
    } else if (type === "seo-meta") {
      const { system, user } = PROMPTS["seo-meta"](title || "", context || "");
      const { text } = await generateText({
        model: openai("gpt-4o-mini"),
        system,
        prompt: user,
      });

      // Спроба парсингу JSON
      try {
        const cleanedText = text.replace(/```json\n?|```/g, "").trim();
        const parsed = JSON.parse(cleanedText);
        result = { success: true, data: parsed };
      } catch (parseError) {
        console.error("[AI SEO] JSON Parse Error:", text);
        result = { success: false, error: "Не вдалося розпарсити відповідь ШІ" };
      }
    } else if (type === "rewrite") {
      const { system, user } = PROMPTS["rewrite"](context || "", mode || "professional");
      const { text } = await generateText({
        model: openai("gpt-4o-mini"),
        system,
        prompt: user,
      });
      result = { success: true, text };
    } else {
      // Зворотна сумісність із старою логікою
      const { system, user } = PROMPTS["product-description"](context || "", tone || "Профессиональный");
      const { text } = await generateText({
        model: openai("gpt-4o-mini"),
        system,
        prompt: user,
      });
      result = { success: true, text };
    }

    return Response.json(result);
  } catch (error) {
    console.error("AI Error:", error);
    return Response.json(
      { success: false, error: "Внутренняя ошибка сервера" },
      { status: 500 }
    );
  }
}

