          // A proper fix would be to add `updateStoreName` to useCart
        }
      }
    }
    updateStoreNames();
  }, [items, mounted]);

  useEffect(() => {
    async function fetchData() {
      if (!session?.user?.id) return;
      const pts = await getUserPoints();
      setPoints(pts);
    }
    fetchData();
  }, [session]);

  useEffect(() => {
    async function fetchUpsell() {
      const upsellIds = items
        .map(i => (i.product as any).upsellProductId)
        .filter(Boolean) as string[];

      if (upsellIds.length > 0) {
        const products = await getProductsByIds(upsellIds);
