            const storeTotal = group.items.reduce((total, item) => total + item.product.price * item.quantity, 0);
            const isGuestCheckout = !session?.user?.id && showGuestFormFor === storeId;

            return (
              <div key={storeId} className="border rounded-xl overflow-hidden bg-white shadow-sm">
                <div className="bg-gray-50 px-6 py-4 border-b flex justify-between items-center">
                  <h2 className="font-bold text-lg flex items-center gap-2">
                    🏪 Продавец: <span className="text-blue-600">{group.storeName}</span>
                  </h2>
                </div>

                <div className="p-6 space-y-4">
                  {group.items.map((item) => (
                    <div key={item.id} className="flex gap-4 items-center">
                      {item.product.imageUrl ? (
                        <Image src={item.product.imageUrl} alt={item.product.name} width={60} height={60} className="rounded-lg object-cover" />
                      ) : (
                        <div className="w-[60px] h-[60px] bg-gray-100 rounded-lg flex items-center justify-center">
                           <span className="text-gray-400 text-xs">Нет фото</span>
                        </div>
                      )}
                      <div className="flex-1">
                        <h3 className="font-semibold text-sm">{item.product.name}</h3>
                        <p className="text-gray-500 text-sm">${item.product.price}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <button onClick={() => updateQuantity(item.id, item.quantity - 1)} className="px-2 border rounded">-</button>
                        <span>{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, item.quantity + 1)} className="px-2 border rounded">+</button>
                      </div>
                      <button onClick={() => removeItem(item.id)} className="text-red-500 ml-4 text-sm hover:underline">Удалить</button>
                    </div>
                  ))}
                </div>

                <div className="bg-gray-50 px-6 py-4 border-t">
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-600">Итого у продавца:</span>
                    <span className="font-bold text-lg">${storeTotal.toFixed(2)}</span>
                  </div>

                  {isGuestCheckout && (
                    <div className="mb-4 p-4 border border-blue-100 bg-blue-50 rounded-lg space-y-3">
                      <h4 className="font-medium text-blue-900 text-sm">Контактные данные для заказа</h4>
                      <div>
                        <input
                          type="text"
                          placeholder="Ваше имя"
                          value={guestName}
                          onChange={(e) => setGuestName(e.target.value)}
