                        onClick={() => showRFQFormFor === storeId ? setShowRFQFormFor(null) : setShowRFQFormFor(storeId)}
                        className="w-full sm:w-auto px-6 py-2.5 rounded-lg font-medium border-2 border-slate-900 text-slate-900 hover:bg-slate-50 disabled:opacity-50 transition-colors whitespace-nowrap"
