import { getCohortData } from "@/actions/analytics";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

interface CohortsPageProps {
  params: Promise<{ storeId: string }>;
}

const formatPrice = (price: number) => {
  return new Intl.NumberFormat("ru-RU", {
    style: "currency",
    currency: "UAH",
  }).format(price);
};

// Кольори для відсотків (від зеленого до червоного)
const getRetentionColor = (rate: number): string => {
  if (rate >= 80) return "bg-green-500 text-white";
  if (rate >= 60) return "bg-green-400 text-white";
  if (rate >= 40) return "bg-yellow-400 text-black";
  if (rate >= 20) return "bg-orange-400 text-white";
  if (rate > 0) return "bg-red-400 text-white";
  return "bg-gray-100 text-gray-400";
};

export default async function CohortsPage({ params }: CohortsPageProps) {
  const { storeId } = await params;
  const cohortData = await getCohortData(storeId);

  // Розрахунок відсотка утримання для кожної когорти
  const cohortsWithRetention = cohortData.map((cohort) => {
    const retentionRate =
      cohort.newCustomers > 0
        ? (cohort.repeatPurchases / cohort.newCustomers) * 100
        : 0;
    return {
      ...cohort,
      retentionRate: Math.round(retentionRate * 10) / 10,
    };
  });

  // Загальна статистика
  const totalCustomers = cohortData.reduce(
    (sum, c) => sum + c.newCustomers,
    0
  );
  const totalRepeatPurchases = cohortData.reduce(
    (sum, c) => sum + c.repeatPurchases,
    0
  );
  const avgRetentionRate =
    cohortData.length > 0
      ? cohortsWithRetention.reduce((sum, c) => sum + c.retentionRate, 0) /
        cohortData.length
      : 0;

  return (
    <div className="flex-col">
      <div className="flex-1 space-y-4 p-8 pt-6">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Когортний аналіз</h2>
          <p className="text-sm text-muted-foreground">
            Утримання клієнтів за місяцями першої покупки
          </p>
        </div>
        <hr className="my-4" />

        {/* KPI Cards */}
        <div className="grid gap-4 grid-cols-1 md:grid-cols-3">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                Всього когорт
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{cohortData.length}</div>
              <p className="text-xs text-muted-foreground">
                Місяців з покупками
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                Всього клієнтів
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{totalCustomers}</div>
              <p className="text-xs text-muted-foreground">
                У всіх когортах
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                Середнє утримання
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {Math.round(avgRetentionRate)}%
              </div>
              <p className="text-xs text-muted-foreground">
                Повторних покупок на когорту
              </p>
            </CardContent>
          </Card>
        </div>

        {/* Cohort Table */}
        <div className="mt-8">
          <h3 className="text-xl font-semibold mb-4">Деталізація по когортах</h3>
          <Card>
            <CardHeader>
              <CardTitle>Когортна таблиця</CardTitle>
            </CardHeader>
            <CardContent>
              {cohortData.length === 0 ? (
                <div className="flex items-center justify-center h-32 text-muted-foreground">
                  Немає даних для когортного аналізу
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Когорта (місяць)</TableHead>
                      <TableHead className="text-right">
                        Нових клієнтів
                      </TableHead>
                      <TableHead className="text-right">
                        Повторних покупок
                      </TableHead>
                      <TableHead className="text-right">
                        % утримання
                      </TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {cohortsWithRetention.map((cohort) => (
                      <TableRow key={cohort.cohortMonth}>
                        <TableCell className="font-medium">
                          {cohort.cohortMonth}
                        </TableCell>
                        <TableCell className="text-right">
                          {cohort.newCustomers}
                        </TableCell>
                        <TableCell className="text-right">
                          {cohort.repeatPurchases}
                        </TableCell>
                        <TableCell className="text-right">
                          <span
                            className={`inline-block px-3 py-1 rounded-full text-sm font-medium ${getRetentionColor(
                              cohort.retentionRate
                            )}`}
                          >
                            {cohort.retentionRate}%
                          </span>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Info Box */}
        <Card className="mt-4 bg-blue-50 dark:bg-blue-950 border-blue-200 dark:border-blue-800">
          <CardContent className="p-4">
            <p className="text-sm text-blue-800 dark:text-blue-200">
              <strong>Як читати когортний аналіз:</strong> Кожна когорта — це
              клієнти, які зробили першу покупку в певному місяці. % утримання
              показує, скільки з них зробили повторні покупки. Зелений колір —
              високе утримання (понад 60%), жовтий — середнє (20-60%), червоний —
              низьке (менше 20%).
            </p>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

