import { getConversionFunnel } from "@/actions/analytics";
import { FunnelClient } from "./client";

interface FunnelPageProps {
  params: Promise<{ storeId: string }>;
  searchParams: Promise<{ from?: string; to?: string }>;
}

export default async function FunnelPage({ params, searchParams }: FunnelPageProps) {
  const { storeId } = await params;
  const { from, to } = await searchParams;

  const dateTo = to ? new Date(to) : new Date();
  const dateFrom = from ? new Date(from) : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

  const data = await getConversionFunnel(storeId, dateFrom, dateTo);

  return <FunnelClient data={data} storeId={storeId} />;
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Banner } from "@prisma/client";
import { Plus, Trash, Edit, Image as ImageIcon } from "lucide-react";
import { toast } from "sonner";
import { deleteBanner } from "@/actions/banner";
import Link from "next/link";
import Image from "next/image";

interface BannersClientProps {
  data: Banner[];
  storeId: string;
}

export const BannersClient: React.FC<BannersClientProps> = ({ data, storeId }) => {
  const router = useRouter();
  const [loadingId, setLoadingId] = useState<string | null>(null);

  const onDelete = async (id: string) => {
    try {
      setLoadingId(id);
      const res = await deleteBanner(storeId, id);
      if (res.error) {
        toast.error(res.error);
      } else {
        toast.success(res.success);
        router.refresh();
      }
    } catch (error) {
      toast.error("Что-то пошло не так.");
    } finally {
      setLoadingId(null);
    }
  };

  return (
    <>
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Баннеры</h2>
          <p className="text-sm text-muted-foreground">
            Управление рекламными баннерами для вашего магазина ({data.length})
          </p>
        </div>
        <Link
          href={`/dashboard/${storeId}/banners/new`}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
        >
          <Plus className="h-4 w-4" />
          Добавить баннер
        </Link>
      </div>

      <div className="mt-8 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {data.length === 0 ? (
          <div className="col-span-full bg-white border border-gray-200 rounded-lg p-12 text-center text-gray-500 shadow-sm flex flex-col items-center">
            <ImageIcon className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            У вас пока нет баннеров.
            <Link href={`/dashboard/${storeId}/banners/new`} className="text-blue-600 hover:text-blue-700 mt-2 font-medium">
              Создайте первый!
            </Link>
          </div>
        ) : (
