                </div>
                <div className="absolute bottom-3 left-4 right-4 text-white">
                  <h3 className="text-lg font-bold truncate">{banner.title}</h3>
                </div>
              </div>
              <div className="p-4 flex-1 flex flex-col">
                <div className="flex justify-between items-center mb-3">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                    banner.location === 'HOME' ? 'bg-blue-100 text-blue-800' : 
                    banner.location === 'SIDEBAR' ? 'bg-purple-100 text-purple-800' : 
                    'bg-gray-100 text-gray-800'
                  }`}>
                    {banner.location === 'HOME' ? 'Главная' : 
                     banner.location === 'SIDEBAR' ? 'Боковая панель' : 'Каталог'}
                  </span>
                  <span className="text-xs text-gray-500">
                    Порядок: {(banner as any).sortOrder}
                  </span>
                </div>
                {banner.link ? (
                  <p className="text-sm text-gray-600 truncate mb-4 flex-1">
                    Ссылка: <a href={banner.link} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline">{banner.link}</a>
                  </p>
                ) : (
                  <p className="text-sm text-gray-400 italic mb-4 flex-1">Нет ссылки</p>
                )}

                <div className="flex justify-between items-center pt-4 border-t border-gray-100">
                  <Link
                    href={`/dashboard/${storeId}/banners/${banner.id}/edit`}
                    className="flex items-center text-sm text-blue-600 hover:text-blue-700 font-medium"
                  >
                    <Edit className="h-4 w-4 mr-1" />
                    Редактировать
                  </Link>
                  <button 
                    onClick={() => {
                      if (confirm("Вы уверены, что хотите удалить этот баннер?")) {
                        onDelete(banner.id);
                      }
                    }}
                    disabled={loadingId === banner.id}
                    className="flex items-center text-sm text-red-600 hover:text-red-700 font-medium disabled:opacity-50"
                  >
                    <Trash className="h-4 w-4 mr-1" />
                    {loadingId === banner.id ? "Удаление..." : "Удалить"}
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </>
  );
};

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Banner } from "@prisma/client";
import { toast } from "sonner";
import { bannerSchema, BannerInput, BannerFormValues } from "@/lib/validations/banner";
import { createBanner, updateBanner } from "@/actions/banner";
import Link from "next/link";
import { ArrowLeft, Image as ImageIcon, Loader2 } from "lucide-react";

interface BannerFormProps {
  initialData?: Banner | null;
  storeId: string;
}

export const BannerForm: React.FC<BannerFormProps> = ({ initialData, storeId }) => {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [imagePreview, setImagePreview] = useState<string | null>(initialData?.imageUrl || null);

  const title = initialData ? "Редактировать баннер" : "Создать баннер";
  const description = initialData ? "Изменить настройки существующего баннера" : "Добавить новый баннер в магазин";
  const toastMessage = initialData ? "Баннер обновлен" : "Баннер создан";
  const action = initialData ? "Сохранить изменения" : "Создать";

  const form = useForm<BannerFormValues>({
    resolver: zodResolver(bannerSchema),
    defaultValues: initialData ? {
      title: initialData.title,
      imageUrl: initialData.imageUrl,
      link: initialData.link || "",
      location: initialData.location,
      isActive: (initialData as any).isActive ?? true,
      sortOrder: (initialData as any).sortOrder ?? 0,
    } : {
      title: "",
      imageUrl: "",
      link: "",
      location: "HOME",
      isActive: true,
      sortOrder: 0,
    },
  });

  const onSubmit = async (data: BannerFormValues) => {
    try {
      setLoading(true);
      // Приводим данные к нужному формату для API
      const apiData: any = { ...data };
      if (apiData.link === "") apiData.link = undefined;

      if (initialData) {
        const res = await updateBanner(storeId, initialData.id, apiData as BannerInput);
        if (res.error) {
          toast.error(res.error);
          return;
        }
      } else {
        const res = await createBanner(storeId, apiData as BannerInput);
        if (res.error) {
          toast.error(res.error);
          return;
        }
      }
      toast.success(toastMessage);
      router.push(`/dashboard/${storeId}/banners`);
      router.refresh();
    } catch (error) {
      toast.error("Что-то пошло не так.");
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        setLoading(true);
        const formData = new FormData();
        formData.append("file", file);

        const response = await fetch("/api/upload", {
          method: "POST",
          body: formData,
        });

        if (!response.ok) {
          throw new Error("Failed to upload image");
        }

        const data = await response.json();
        form.setValue("imageUrl", data.url);
        setImagePreview(data.url);
        toast.success("Изображение загружено");
      } catch (error) {
        console.error(error);
        toast.error("Ошибка загрузки изображения");
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <>
      <div className="flex items-center gap-4">
        <Link 
          href={`/dashboard/${storeId}/banners`}
          className="p-2 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
        >
          <ArrowLeft className="h-5 w-5 text-gray-500" />
        </Link>
        <div>
          <h2 className="text-3xl font-bold tracking-tight">{title}</h2>
          <p className="text-sm text-muted-foreground">
            {description}
          </p>
        </div>
      </div>

      <div className="mt-8 bg-white border border-gray-200 rounded-lg shadow-sm p-6">
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8 max-w-3xl">
          <div className="space-y-4">

            <div className="flex flex-col gap-2">
              <label className="text-sm font-medium text-gray-700">Изображение баннера</label>
              <div className="flex items-center gap-4">
                <div 
                  className="w-full max-w-md aspect-video border-2 border-dashed border-gray-300 rounded-lg overflow-hidden flex items-center justify-center bg-gray-50 relative"
                >
                  {imagePreview ? (
                    <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <div className="flex flex-col items-center text-gray-400">
                      <ImageIcon className="h-10 w-10 mb-2 opacity-50" />
                      <span className="text-sm">Загрузите изображение</span>
                    </div>
                  )}
                  {loading && (
                    <div className="absolute inset-0 bg-white/50 flex items-center justify-center backdrop-blur-sm">
                      <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
                    </div>
                  )}
                </div>
                <div className="flex flex-col gap-2">
                  <label className="bg-blue-50 text-blue-600 border border-blue-200 px-4 py-2 rounded-md font-medium text-sm text-center cursor-pointer hover:bg-blue-100 transition-colors">
                    Выбрать файл
                    <input 
                      type="file" 
                      accept="image/*" 
                      className="hidden" 
                      onChange={handleImageUpload}
                      disabled={loading}
                    />
                  </label>
                  {form.formState.errors.imageUrl && (
                    <p className="text-xs text-red-500">{form.formState.errors.imageUrl.message}</p>
                  )}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Заголовок (внутреннее название)</label>
                <input
                  disabled={loading}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm disabled:opacity-50"
                  placeholder="Летняя распродажа"
                  {...form.register("title")}
                />
                {form.formState.errors.title && (
                  <p className="text-xs text-red-500">{form.formState.errors.title.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Ссылка (опционально)</label>
                <input
                  disabled={loading}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm disabled:opacity-50"
                  placeholder="https://... или /category/..."
                  {...form.register("link")}
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Расположение</label>
                <select
                  disabled={loading}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm disabled:opacity-50"
                  {...form.register("location")}
                >
                  <option value="HOME">Главная страница</option>
                  <option value="CATALOG">Каталог</option>
                  <option value="SIDEBAR">Сайдбар</option>
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Порядок сортировки</label>
                <input
                  type="number"
                  disabled={loading}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm disabled:opacity-50"
                  {...form.register("sortOrder", { valueAsNumber: true })}
                />
              </div>
            </div>

            <div className="flex items-center gap-2 pt-2">
              <input
                type="checkbox"
                id="isActive"
                disabled={loading}
                className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                {...form.register("isActive")}
              />
              <label htmlFor="isActive" className="text-sm font-medium text-gray-700">
                Баннер активен (показывается клиентам)
              </label>
            </div>
          </div>

          <div className="pt-6 border-t border-gray-200">
            <button
              type="submit"
              disabled={loading}
              className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center font-medium"
            >
              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {action}
            </button>
          </div>
        </form>
      </div>
    </>
  );
};

"use client";

import { useBuilder } from "@/hooks/use-builder";
