import { 
  DndContext, 
  closestCenter, 
  PointerSensor, 
  KeyboardSensor, 
  useSensor, 
  useSensors,
  DragEndEvent 
} from "@dnd-kit/core";
import { 
  SortableContext, 
  sortableKeyboardCoordinates, 
  verticalListSortingStrategy 
} from "@dnd-kit/sortable";
import { SortableBlock } from "@/modules/builder/components/sortable-block";

interface ClientBuilderProps {
  pageId: string;
  pageName: string;
  initialBlocks: EditorBlock[];
}

export function ClientBuilder({ pageId, pageName, initialBlocks }: ClientBuilderProps) {
  const {
    blocks,
    selectedBlockId,
    addBlock,
    selectBlock,
    updateBlock,
    removeBlock,
    setBlocks,
    reorderBlocksById,
  } = useBuilder();

  const [isSaving, setIsSaving] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const params = useParams();

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  // Hydration стейта при монтировании компонента
  useEffect(() => {
    setBlocks(initialBlocks);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pageId]);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;

    if (over && active.id !== over.id) {
      reorderBlocksById(String(active.id), String(over.id));
    }
  }, [reorderBlocksById]);

  const handleAddBlock = (type: BlockType) => {
    const newBlock: EditorBlock = {
      id: crypto.randomUUID(),
      type,
      content: getDefaultContent(type),
      styles: {},
    };
    addBlock(newBlock);
  };

  const handleSave = async () => {
    setIsSaving(true);
    const result = await savePageContent(pageId, blocks);
    if (result.error) {
      toast.error(result.error);
    } else {
      toast.success(result.success);
    }
    setIsSaving(false);
  };

  const handleGenerateText = async (blockId: string, context: string) => {
    setIsGenerating(true);
    try {
      const response = await fetch('/api/ai/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ context, storeId: params.storeId }),
      });
      const data = await response.json();
      if (data.success) {
        updateBlock(blockId, { content: { text: data.text } } as any);
      } else {
        toast.error(data.error || "Ошибка генерации текста");
      }
    } catch (error) {
      toast.error("Что-то пошло не так при генерации текста");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImageUpload = async (e: ChangeEvent<HTMLInputElement>, blockId: string) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        const formData = new FormData();
        formData.append("file", file);

        const response = await fetch("/api/upload", {
          method: "POST",
          body: formData,
        });

        if (!response.ok) {
          throw new Error("Failed to upload image");
        }

        const data = await response.json();
        updateBlock(blockId, { content: { src: data.url } } as any);
        toast.success("Изображение загружено");
      } catch (error) {
        console.error(error);
        toast.error("Ошибка загрузки изображения");
      }
    }
  };

  const selectedBlock = blocks.find((b) => b.id === selectedBlockId);

  return (
    <div className="flex flex-col h-[calc(100vh-4rem)] -m-8 bg-gray-100 overflow-hidden">
