// Утилита для рендера блока на холсте
function BlockRenderer({ block }: { block: EditorBlock }) {
  switch (block.type) {
    case "Hero":
      return (
        <div className="py-20 px-8 text-center bg-gray-50">
          <h1 className="text-4xl font-bold mb-4">{block.content.title}</h1>
          <p className="text-xl text-gray-600">{block.content.subtitle}</p>
        </div>
      );
    case "Heading":
      return <h2 className="text-2xl font-bold p-4">{block.content.text}</h2>;
    case "Paragraph":
      return <p className="text-base text-gray-700 p-4">{block.content.text}</p>;
    case "Image":
      return (
        <div className="p-4">
          <img 
            src={block.content.src || "https://via.placeholder.com/800x400"} 
            alt={block.content.alt}
            className="w-full h-auto object-cover rounded-md"
          />
        </div>
      );
    case "ProductGrid":
      return (
        <div className="py-12 px-8 bg-white border-2 border-dashed border-gray-200 m-4 rounded-xl text-center">
          <h3 className="text-2xl font-bold mb-4">{block.content.title}</h3>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 opacity-50">
            {[...Array(Number(block.content.limit) || 4)].map((_, i) => (
              <div key={i} className="bg-gray-100 h-48 rounded-lg animate-pulse"></div>
            ))}
          </div>
          <p className="mt-4 text-sm text-gray-400">
            Здесь будет выведена реальная сетка товаров на витрине магазина.
          </p>
        </div>
      );
    case "BannerSlider":
      return (
        <div className="h-64 bg-gradient-to-r from-blue-500 to-purple-600 flex items-center justify-center border-2 border-dashed border-blue-300 m-4 rounded-xl">
          <div className="text-white text-center">
            <svg className="w-12 h-12 mx-auto mb-2 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            <p className="font-medium">Баннер-карусель</p>
            <p className="text-sm opacity-75">Баннеры подтягиваются из раздела "Баннеры"</p>
          </div>
        </div>
      );
    case "Accordion":
      return (
        <div className="p-4 space-y-2">
          <h3 className="text-xl font-bold mb-4">{block.content.title}</h3>
          {(block.content.items as { question: string; answer: string }[]).map((item, i) => (
            <div key={i} className="border rounded p-3 bg-gray-50">
              <div className="font-medium">{item.question}</div>
              <div className="text-sm text-gray-600 mt-1">{item.answer}</div>
            </div>
          ))}
        </div>
      );
    case "DropdownMenu":
      return (
        <div className="p-4 inline-block">
          <div className="bg-blue-600 text-white px-4 py-2 rounded cursor-pointer">{block.content.label} ▾</div>
          {/* Simulated dropdown */}
          <div className="mt-1 border rounded shadow-md bg-white opacity-50 absolute pointer-events-none">
            {(block.content.items as { label: string; href: string }[]).map((item, i) => (
              <div key={i} className="px-4 py-2 hover:bg-gray-100 text-sm border-b last:border-0">{item.label}</div>
            ))}
          </div>
        </div>
      );
    case "PopupBanner":
      return (
        <div className="p-8 border-2 border-dashed border-purple-300 bg-purple-50 rounded-xl relative">
          <div className="absolute top-2 right-2 text-xs bg-purple-200 text-purple-800 px-2 py-1 rounded">Popup (Preview)</div>
          <h3 className="text-2xl font-bold text-purple-900">{block.content.title}</h3>
          <p className="mt-2 text-purple-800">{block.content.message}</p>
          <button className="mt-4 bg-purple-600 text-white px-6 py-2 rounded-full">{block.content.buttonText}</button>
          <div className="mt-4 text-xs text-gray-500">
            Trigger: {block.settings?.trigger || 'onLoad'} {block.settings?.delayInSeconds ? `(${block.settings.delayInSeconds}s)` : ''}
          </div>
        </div>
      );
    case "GridContainer":
      return (
        <div 
          className="p-4 bg-gray-50"
          style={{
            display: 'grid',
            gridTemplateColumns: `repeat(${block.content.columns || 12}, 1fr)`,
            gap: block.content.gap || '16px'
          }}
        >
          {(block.content.items as any[]).map((item, i) => (
            <div 
              key={item.id} 
              className="border-2 border-dashed border-gray-300 bg-white min-h-[100px] flex flex-col items-center justify-center p-2 text-sm text-gray-400"
              style={{
                gridColumn: `span ${item.colSpan || 4}`,
                gridRow: `span ${item.rowSpan || 1}`
              }}
            >
              Ячейка сетки (col: {item.colSpan}, row: {item.rowSpan})
            </div>
          ))}
        </div>
      );
    default:
      return <div>Unknown Block</div>;
  }
}

// Утилита для дефолтного контента
function getDefaultContent(type: BlockType): any {
  switch (type) {
    case "Hero":
      return { title: "Новый заголовок Hero", subtitle: "Подзаголовок для описания" };
    case "Heading":
      return { text: "Заголовок блока" };
    case "Paragraph":
      return { text: "Это базовый текстовый параграф." };
    case "Image":
      return { src: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=2564&auto=format&fit=crop", alt: "Изображение" };
    case "ProductGrid":
      return { title: "Наши товары", limit: "4" };
    case "BannerSlider":
      return { autoPlay: true, interval: "5000", showDots: true };
    case "Video":
      return { src: "https://www.youtube.com/embed/dQw4w9WgXcQ" };
    case "Button":
      return { text: "Нажмите здесь", href: "#" };
    case "Divider":
      return {};
    case "Columns":
      return {
        columns: [
          { id: crypto.randomUUID(), width: '50%', blocks: [] },
          { id: crypto.randomUUID(), width: '50%', blocks: [] }
        ]
      };
    case "CountdownTimer":
      const nextWeek = new Date();
      nextWeek.setDate(nextWeek.getDate() + 7);
      return { title: "До конца акции осталось:", targetDate: nextWeek.toISOString() };
    case "NewsletterForm":
      return { title: "Подпишитесь на новости", subtitle: "Получайте обновления о новых поступлениях и скидках", placeholder: "Ваш email", buttonText: "Подписаться" };
    case "Accordion":
      return { title: "Частые вопросы", items: [{ question: "Вопрос 1", answer: "Ответ 1" }, { question: "Вопрос 2", answer: "Ответ 2" }] };
    case "DropdownMenu":
      return { label: "Категории", items: [{ label: "Пункт 1", href: "#" }, { label: "Пункт 2", href: "#" }] };
    case "PopupBanner":
      return { title: "Специальное предложение!", message: "Скидка 20% на первый заказ", buttonText: "Получить скидку", buttonHref: "#" };
    case "GridContainer":
      return {
        columns: 12,
        gap: "16px",
        items: [
          { id: crypto.randomUUID(), colSpan: 8, rowSpan: 2, blocks: [] },
          { id: crypto.randomUUID(), colSpan: 4, rowSpan: 1, blocks: [] },
          { id: crypto.randomUUID(), colSpan: 4, rowSpan: 1, blocks: [] }
        ]
      };
    default:
      return {};
  }
}

