'use client';

import { useState, useEffect } from 'react';
import { getCustomerGroups, saveCustomerGroup, deleteCustomerGroup } from '@/actions/customer-groups';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Plus, Pencil, Trash2, Users } from 'lucide-react';

interface CustomerGroup {
  id: string;
  name: string;
  discountPercentage: number;
  userCount: number;
  priceCount: number;
}

interface CustomerGroupsClientProps {
  storeId: string;
  storeName: string;
}

export function CustomerGroupsClient({ storeId, storeName }: CustomerGroupsClientProps) {
  const [groups, setGroups] = useState<CustomerGroup[]>([]);
  const [loading, setLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingGroup, setEditingGroup] = useState<CustomerGroup | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    discountPercentage: 0,
    description: '',
  });

  const loadGroups = async () => {
    setLoading(true);
    const result = await getCustomerGroups(storeId);
    if (result.success) {
      setGroups(result.data);
    }
    setLoading(false);
  };

  useEffect(() => {
    loadGroups();
  }, [storeId]);

  const handleOpenChange = (open: boolean) => {
    setIsDialogOpen(open);
    if (!open) {
      setEditingGroup(null);
      setFormData({ name: '', discountPercentage: 0, description: '' });
    }
  };

  const handleEdit = (group: CustomerGroup) => {
    setEditingGroup(group);
    setFormData({
      name: group.name,
      discountPercentage: group.discountPercentage,
      description: '',
    });
    setIsDialogOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();

    const result = await saveCustomerGroup(storeId, {
      id: editingGroup?.id,
      name: formData.name,
      discountPercentage: formData.discountPercentage,
    });

    if (result.success) {
      loadGroups();
      handleOpenChange(false);
    } else {
      alert(result.error || 'Помилка збереження');
    }
  };

  const handleDelete = async (groupId: string) => {
    if (!confirm('Ви впевнені, що хочете видалити цю групу?')) return;

    const result = await deleteCustomerGroup(groupId, storeId);
    if (result.success) {
      loadGroups();
    } else {
      alert(result.error || 'Помилка видалення');
    }
  };

  return (
    <div className="container mx-auto p-6">
      <div className="mb-6">
        <h1 className="text-3xl font-bold">Групи клієнтів</h1>
        <p className="text-gray-500">Керування групами клієнтів для магазину "{storeName}"</p>
      </div>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Список груп</CardTitle>
            <CardDescription>
              Створіть групи клієнтів для застосування знижок до певних категорій покупців
            </CardDescription>
          </div>
          <Dialog open={isDialogOpen} onOpenChange={handleOpenChange}>
            <DialogTrigger asChild>
              <Button onClick={() => {
                setEditingGroup(null);
                setFormData({ name: '', discountPercentage: 0, description: '' });
              }}>
                <Plus className="w-4 h-4 mr-2" />
                Створити групу
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>
                  {editingGroup ? 'Редагувати групу' : 'Нова група клієнтів'}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSave} className="space-y-4">
                <div>
                  <Label htmlFor="name">Назва групи</Label>
                  <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    placeholder="Наприклад: Оптові покупці"
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="discount">Відсоток знижки (%)</Label>
                  <Input
                    id="discount"
                    type="number"
                    min="0"
                    max="100"
                    value={formData.discountPercentage}
                    onChange={(e) => setFormData({ ...formData, discountPercentage: Number(e.target.value) })}
                    required
                  />
                </div>
                <div className="flex justify-end gap-2">
                  <Button type="button" variant="outline" onClick={() => handleOpenChange(false)}>
                    Скасувати
                  </Button>
                  <Button type="submit">
                    {editingGroup ? 'Зберегти' : 'Створити'}
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="text-center py-8 text-gray-500">Завантаження...</div>
          ) : groups.length === 0 ? (
            <div className="text-center py-8 text-gray-500">
              Немає жодної групи клієнтів. Створіть першу групу.
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Назва</TableHead>
                  <TableHead>Знижка</TableHead>
                  <TableHead>Кількість користувачів</TableHead>
                  <TableHead>С1іни продуктів</TableHead>
                  <TableHead className="text-right">Дії</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {groups.map((group) => (
                  <TableRow key={group.id}>
                    <TableCell className="font-medium">{group.name}</TableCell>
                    <TableCell>
                      <Badge variant={group.discountPercentage > 0 ? 'default' : 'secondary'}>
                        {group.discountPercentage}%
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-1">
                        <Users className="w-4 h-4 text-gray-500" />
                        {group.userCount}
                      </div>
                    </TableCell>
                    <TableCell>{group.priceCount}</TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleEdit(group)}
                        >
                          <Pencil className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleDelete(group.id)}
                        >
                          <Trash2 className="w-4 h-4 text-red-500" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";
import {
  createWarehouse,
  addStockMovement,
  getWarehouseStock,
  getStockMovements,
} from "@/actions/inventory";
import { toast } from "sonner";
import {
  Warehouse,
  Package,
  Plus,
  TrendingUp,
  TrendingDown,
  ArrowLeftRight,
  AlertTriangle,
  BarChart3,
  RefreshCw,
} from "lucide-react";

// ─── Типы ─────────────────────────────────────────────────────────────────────

interface WarehouseItem {
  id: string;
  name: string;
  address: string | null;
  isDefault: boolean;
  _count: { stock: number };
}

interface ProductItem {
  id: string;
  name: string;
  imageUrl: string | null;
  stock: number;
}

interface InventoryStats {
  warehousesCount: number;
  totalProducts: number;
  totalQuantity: number;
  totalAvailable: number;
  totalReserved: number;
  lowStockCount: number;
}

interface InventoryClientProps {
  storeId: string;
  warehouses: WarehouseItem[];
  products: ProductItem[];
  stats: InventoryStats;
  selectedWarehouseId?: string;
  abcAnalysis?: { id: string; name: string; revenue: number; category: "A" | "B" | "C" }[];
}

// ─── Модальное окно создания склада ───────────────────────────────────────────

function CreateWarehouseModal({
  storeId,
  onClose,
  onCreated,
}: {
  storeId: string;
  onClose: () => void;
  onCreated: () => void;
}) {
  const [name, setName] = useState("");
  const [address, setAddress] = useState("");
  const [isDefault, setIsDefault] = useState(false);
  const [isPending, startTransition] = useTransition();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    startTransition(async () => {
      const result = await createWarehouse({ storeId, name, address, isDefault });
      if (result.success) {
        toast.success("Склад создан");
        onCreated();
        onClose();
      } else {
        toast.error(result.error ?? "Ошибка создания склада");
      }
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-white dark:bg-slate-800 rounded-xl p-6 w-full max-w-md shadow-xl">
        <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-4">Создать склад</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Название *
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              placeholder="Главный склад"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Адрес
            </label>
            <input
              type="text"
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="ул. Примерная, 1"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <label className="flex items-center gap-3 cursor-pointer">
            <input
              type="checkbox"
              checked={isDefault}
              onChange={(e) => setIsDefault(e.target.checked)}
              className="w-4 h-4 rounded border-slate-300 text-blue-600"
            />
            <span className="text-sm text-slate-700 dark:text-slate-300">Склад по умолчанию</span>
          </label>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
            >
              Отмена
            </button>
            <button
              type="submit"
              disabled={isPending}
              className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-medium rounded-lg"
            >
              {isPending ? "Создание..." : "Создать"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─── Модальное окно движения стока ────────────────────────────────────────────

function StockMovementModal({
  warehouseId,
  products,
  onClose,
  onDone,
}: {
  warehouseId: string;
  products: ProductItem[];
  onClose: () => void;
  onDone: () => void;
}) {
  const [productId, setProductId] = useState(products[0]?.id ?? "");
  const [type, setType] = useState<"RECEIPT" | "SALE" | "RETURN" | "ADJUSTMENT" | "TRANSFER">("RECEIPT");
  const [quantity, setQuantity] = useState("1");
  const [reason, setReason] = useState("");
  const [isPending, startTransition] = useTransition();

  const MOVEMENT_TYPES = [
    { value: "RECEIPT", label: "Поступление", icon: TrendingUp, color: "text-green-600" },
    { value: "SALE", label: "Продажа", icon: TrendingDown, color: "text-red-600" },
    { value: "RETURN", label: "Возврат", icon: RefreshCw, color: "text-blue-600" },
    { value: "ADJUSTMENT", label: "Корректировка", icon: ArrowLeftRight, color: "text-purple-600" },
    { value: "TRANSFER", label: "Перемещение", icon: ArrowLeftRight, color: "text-orange-600" },
  ];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    startTransition(async () => {
      const result = await addStockMovement({
        warehouseId,
        productId,
        type,
        quantity: parseInt(quantity, 10),
        reason,
      });
      if (result.success) {
        toast.success("Движение товара записано");
        onDone();
        onClose();
      } else {
        toast.error(result.error ?? "Ошибка");
      }
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-white dark:bg-slate-800 rounded-xl p-6 w-full max-w-md shadow-xl">
        <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-4">
          Добавить движение товара
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Товар *
            </label>
            <select
              value={productId}
              onChange={(e) => setProductId(e.target.value)}
              required
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {products.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name} (остаток: {p.stock})
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Тип движения *
            </label>
            <div className="grid grid-cols-2 gap-2">
              {MOVEMENT_TYPES.map((mt) => (
                <button
                  key={mt.value}
                  type="button"
                  onClick={() => setType(mt.value as typeof type)}
                  className={`flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-lg border transition-colors ${
                    type === mt.value
                      ? "border-blue-500 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300"
                      : "border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700"
                  }`}
                >
                  <mt.icon className={`w-4 h-4 ${mt.color}`} />
                  {mt.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Количество *
            </label>
            <input
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              required
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Причина / Комментарий
            </label>
            <input
              type="text"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Необязательно"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
            >
              Отмена
            </button>
            <button
              type="submit"
              disabled={isPending}
              className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-medium rounded-lg"
            >
              {isPending ? "Запись..." : "Записать"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

