                              </td>
                              <td className="px-4 py-3 text-sm text-slate-500 dark:text-slate-400 text-right">
                                {new Date(mv.createdAt).toLocaleDateString("ru-RU")}
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Модальное окно создания склада */}
      {showCreateModal && (
        <CreateWarehouseModal
          storeId={storeId}
          onClose={() => setShowCreateModal(false)}
          onCreated={() => router.refresh()}
        />
      )}

      {/* Модальное окно движения товара */}
      {showMovementModal && activeWarehouseId && (
        <StockMovementModal
          warehouseId={activeWarehouseId}
          products={products}
          onClose={() => setShowMovementModal(false)}
          onDone={() => loadWarehouseData(activeWarehouseId)}
        />
      )}
    </div>
  );
}

