// ─── Order Timeline Component ─────────────────────────────────────────────────

interface StatusHistoryEntry {
  status: string;
  previousStatus?: string;
  changedAt: string;
  changedBy?: string;
}

function OrderTimeline({ history }: { history?: any[] }) {
  if (!history || history.length === 0) {
    return (
      <div className="text-sm text-gray-500 text-center py-4">
        Історія змін статусу відсутня
      </div>
    );
  }

  const getStatusLabel = (status: string) => {
    const labels: Record<string, string> = {
      PENDING: "Новий",
      PROCESSING: "В обробці",
      SHIPPED: "Відправлено",
      COMPLETED: "Виконано",
      CANCELLED: "Скасовано",
      REFUND_REQUESTED: "Запит на поверхнення",
      REFUNDED: "Повернено",
    };
    return labels[status] || status;
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      PENDING: "bg-yellow-500",
      PROCESSING: "bg-blue-500",
      SHIPPED: "bg-purple-500",
      COMPLETED: "bg-green-500",
      CANCELLED: "bg-red-500",
      REFUND_REQUESTED: "bg-orange-500",
      REFUNDED: "bg-indigo-500",
    };
    return colors[status] || "bg-gray-500";
  };

  return (
    <div className="relative">
      <div className="absolute left-4 top-0 bottom-0 w-0.5 bg-gray-200" />
      <div className="space-y-6 pl-4">
        {history.map((entry: StatusHistoryEntry, index: number) => (
          <div key={index} className="relative flex items-start gap-4">
            <div
              className={`w-8 h-8 rounded-full ${getStatusColor(entry.status)} flex items-center justify-center text-white text-xs font-bold z-10 flex-shrink-0`}
            >
              {index + 1}
            </div>
            <div className="flex-1 bg-white border border-gray-200 rounded-lg p-3 shadow-sm">
              <div className="flex justify-between items-center mb-1">
                <span className="font-semibold text-gray-900">
                  {getStatusLabel(entry.status)}
                </span>
                <span className="text-xs text-gray-500">
                  {entry.changedAt
                    ? format(new Date(entry.changedAt), "dd.MM.yyyy HH:mm", {
                        locale: ru,
                      })
                    : ""}
                </span>
              </div>
              {entry.previousStatus && (
                <div className="text-xs text-gray-500">
                  Previous: {getStatusLabel(entry.previousStatus)}
                </div>
              )}
              {entry.changedBy && (
                <div className="text-xs text-gray-400 mt-1">
                  Змінив: {entry.changedBy}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

