// ─── Fraud Panel Component ────────────────────────────────────────────────────

interface FraudPanelProps {
  fraudScore: number | null | undefined;
  fraudFlags: string[] | undefined;
  fraudStatus: string | null | undefined;
  orderId: string;
  storeId: string;
  onApprove: () => void;
}

function FraudPanel({ fraudScore, fraudFlags, fraudStatus, orderId, storeId, onApprove }: FraudPanelProps) {
  const [loading, setLoading] = useState(false);
  const score = fraudScore ?? 0;

  const getScoreColor = (s: number) => {
    if (s >= 80) return "bg-red-500";
    if (s >= 50) return "bg-yellow-500";
    return "bg-green-500";
  };

  const getFlagLabel = (flag: string) => {
    const labels: Record<string, string> = {
      HIGH_VALUE: "Замовлення з високою сумою",
      NEW_CUSTOMER: "Новий клієнт",
      MULTIPLE_ADDRESSES: "Кілька адрес доставки",
      VELOCITY: "Багато замовлень за короткий час",
      IP_MISMATCH: "IP адреса не збігається",
      CARD_TESTING: "Підозра на тестування картки",
    };
    return labels[flag] || flag;
  };

  const handleApprove = async () => {
    setLoading(true);
    try {
      const result = await approveFraudOrder(orderId, storeId);
      if (result.success) {
        toast.success(result.success);
        onApprove();
      } else {
        toast.error(result.error || "Помилка схвалення");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
      <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <svg className="w-5 h-5 text-red-500" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
          </svg>
          <h2 className="font-semibold text-gray-900">Перевірка безпеки</h2>
        </div>
        {fraudStatus !== 'SAFE' && (
          <button
            onClick={handleApprove}
            disabled={loading}
            className="inline-flex items-center px-3 py-1.5 text-sm font-medium text-white bg-green-600 rounded-lg hover:bg-green-700 disabled:opacity-50"
          >
            {loading ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : '✓ Схвалити'}
          </button>
        )}
      </div>
      <div className="px-6 py-4 space-y-4">
        {/* Score Progress Bar */}
        <div>
          <div className="flex justify-between text-sm mb-1">
            <span className="text-gray-500">Рівень ризику</span>
            <span className={`font-medium ${score >= 80 ? 'text-red-600' : score >= 50 ? 'text-yellow-600' : 'text-green-600'}`}>
              {Math.round(score)}%
            </span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-2.5">
            <div
              className={`h-2.5 rounded-full ${getScoreColor(score)}`}
              style={{ width: `${Math.min(score, 100)}%` }}
            />
          </div>
        </div>

        {/* Fraud Flags */}
        {fraudFlags && fraudFlags.length > 0 && (
          <div>
            <p className="text-sm font-medium text-gray-700 mb-2">Прапори ризику:</p>
            <ul className="space-y-1">
              {fraudFlags.map((flag, idx) => (
                <li key={idx} className="text-sm text-gray-600 flex items-center gap-2">
                  <span className="w-1.5 h-1.5 bg-red-500 rounded-full" />
                  {getFlagLabel(flag)}
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Status Badge */}
        <div className="flex items-center gap-2">
          <span className="text-sm text-gray-500">Статус:</span>
          <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
            fraudStatus === 'BLOCKED' ? 'bg-red-100 text-red-800' :
            fraudStatus === 'SUSPICIOUS' ? 'bg-yellow-100 text-yellow-800' :
            'bg-green-100 text-green-800'
          }`}>
            {fraudStatus || 'UNKNOWN'}
          </span>
        </div>
      </div>
    </div>
  );
}

