// ─── TTN Modal ────────────────────────────────────────────────────────────────

interface TTNModalProps {
  orderId: string;
  storeId: string;
  onSuccess: (ttn: string) => void;
  onClose: () => void;
}

function TTNModal({ orderId, storeId, onSuccess, onClose }: TTNModalProps) {
  const [weight, setWeight] = useState("0.5");
  const [declaredValue, setDeclaredValue] = useState("500");
  const [senderWarehouseRef, setSenderWarehouseRef] = useState("");
  const [loading, setLoading] = useState(false);

  const handleCreate = async () => {
    const w = parseFloat(weight);
    const v = parseFloat(declaredValue);

    if (!senderWarehouseRef.trim()) {
      toast.error("Укажите Ref отделения отправителя");
      return;
    }
    if (isNaN(w) || w <= 0) {
      toast.error("Укажите корректный вес");
      return;
    }
    if (isNaN(v) || v <= 0) {
      toast.error("Укажите корректную объявленную стоимость");
      return;
    }

    setLoading(true);
    try {
      const result = await createShipment({
        orderId,
        storeId,
        weight: w,
        declaredValue: v,
        senderWarehouseRef: senderWarehouseRef.trim(),
      });

      if (result.error) {
        toast.error(result.error);
      } else if (result.trackingNumber) {
        toast.success(`ТТН создана: ${result.trackingNumber}`);
        onSuccess(result.trackingNumber);
        onClose();
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-md">
        <div className="p-6 border-b">
          <h2 className="text-lg font-semibold">Создать ТТН Нова Пошта</h2>
          <p className="text-sm text-gray-500 mt-1">
            Заполните параметры отправления
          </p>
        </div>

        <div className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Ref отделения отправителя
            </label>
            <input
              type="text"
              value={senderWarehouseRef}
              onChange={(e) => setSenderWarehouseRef(e.target.value)}
              placeholder="xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <p className="text-xs text-gray-400 mt-1">
              UUID отделения НП, с которого отправляете
            </p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Вес (кг)
            </label>
            <input
              type="number"
              value={weight}
              onChange={(e) => setWeight(e.target.value)}
              min="0.1"
              step="0.1"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Объявленная стоимость (грн)
            </label>
            <input
              type="number"
              value={declaredValue}
              onChange={(e) => setDeclaredValue(e.target.value)}
              min="1"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>

        <div className="p-6 border-t flex gap-3 justify-end">
          <Button variant="outline" onClick={onClose} disabled={loading}>
            Отмена
          </Button>
          <Button onClick={handleCreate} disabled={loading}>
            {loading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
            Создать ТТН
          </Button>
        </div>
      </div>
    </div>
  );
}

