export function OrderDetailClient({ order, storeId }: OrderDetailClientProps) {
  const [trackingNumber, setTrackingNumber] = useState<string | null>(
    order.trackingNumber ?? null
  );
  const [status, setStatus] = useState(order.status);
  const [showTTNModal, setShowTTNModal] = useState(false);
  const [copied, setCopied] = useState(false);
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [isCreatingUkrposhta, setIsCreatingUkrposhta] = useState(false);

  const isUkrposhta = order.deliveryCity?.toLowerCase().includes("укрпошта") || order.deliveryWarehouse?.toLowerCase().includes("укрпошта");
  const isNovaPoshta = !isUkrposhta && (order.deliveryCity || order.deliveryWarehouse);

  const handleCreateUkrposhtaTtn = async () => {
    setIsCreatingUkrposhta(true);
    try {
      const result = await generateUkrposhtaTtn(order.id, storeId);
      if (result.success && result.trackingNumber) {
        toast.success(`ТТН Укрпошти успішно створено: ${result.trackingNumber}`);
        setTrackingNumber(result.trackingNumber);
        setStatus("SHIPPED"); // Or fetch updated order
      } else {
        toast.error(result.error || "Помилка при створенні ТТН Укрпошти");
      }
    } catch (error) {
      toast.error("Непередбачена помилка");
    } finally {
      setIsCreatingUkrposhta(false);
    }
  };

  const handleCopyTTN = async () => {
    if (!trackingNumber) return;
    await navigator.clipboard.writeText(trackingNumber);
    setCopied(true);
    toast.success("ТТН скопирован в буфер обмена");
    setTimeout(() => setCopied(false), 2000);
  };

  const handleStatusChange = async (newStatus: string) => {
    setUpdatingStatus(true);
    try {
      await updateOrderStatus(order.id, storeId, newStatus);
      setStatus(newStatus);
      toast.success(`Статус изменён на "${STATUS_LABELS[newStatus] ?? newStatus}"`);
    } catch {
      toast.error("Ошибка изменения статуса");
    } finally {
      setUpdatingStatus(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8 space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Link
          href={`/dashboard/${storeId}/orders`}
          className="flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-900 transition-colors"
        >
          <ArrowLeft className="w-4 h-4" />
          Назад к заказам
        </Link>
      </div>

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Заказ #{order.id.slice(0, 8).toUpperCase()}
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            {format(new Date(order.createdAt), "d MMMM yyyy, HH:mm", {
              locale: ru,
            })}
          </p>
        </div>

        <div className="flex items-center gap-3 flex-wrap">
          <span
            className={`inline-flex items-center px-3 py-1.5 rounded-full text-sm font-medium ${
              STATUS_COLORS[status] ?? "bg-gray-100 text-gray-700"
            }`}
          >
            {STATUS_LABELS[status] ?? status}
          </span>

          {/* Status change dropdown */}
          <select
            value={status}
            onChange={(e) => handleStatusChange(e.target.value)}
            disabled={updatingStatus}
            className="text-sm border border-gray-300 rounded-lg px-3 py-1.5 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
          >
            {Object.entries(STATUS_LABELS).map(([value, label]) => (
              <option key={value} value={value}>
                {label}
              </option>
            ))}
          </select>

          {/* PDF buttons */}
          <button
            onClick={() =>
              window.open(`/api/orders/${order.id}/pdf?type=invoice`, "_blank")
            }
            className="inline-flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            title="Скачать счёт-фактуру PDF"
          >
            <FileDown className="w-4 h-4" />
            Счёт PDF
          </button>

          <button
            onClick={() =>
              window.open(
                `/api/orders/${order.id}/pdf?type=packing-slip`,
                "_blank"
              )
            }
            className="inline-flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            title="Скачать упаковочный лист PDF"
