          </div>
        </div>

        {/* Fraud Panel - показуємо тільки якщо не SAFE */}
        {order.fraudStatus && order.fraudStatus !== 'SAFE' && (
          <div className="mt-6">
            <FraudPanel
              fraudScore={order.fraudScore}
              fraudFlags={order.fraudFlags}
