        </div>
      </div>

      {/* TTN Modal */}
      {showTTNModal && (
        <TTNModal
          orderId={order.id}
          storeId={storeId}
          onSuccess={(ttn) => setTrackingNumber(ttn)}
          onClose={() => setShowTTNModal(false)}
        />
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { DragDropContext, Droppable, Draggable, DropResult } from "@hello-pangea/dnd";
import { updateOrderStatus, processRefund } from "@/actions/order";
import { toast } from "sonner";
import { Order, OrderItem, Product } from "@prisma/client";
import { format } from "date-fns";
import { ru } from "date-fns/locale";
import { Button } from "@/components/ui/button";

type OrderWithItems = Order & {
  orderItems: (OrderItem & {
    product: Product;
  })[];
};

interface OrderKanbanBoardProps {
  orders: OrderWithItems[];
  storeId: string;
}

const COLUMNS = [
  { id: "PENDING", title: "Новый", color: "border-yellow-200 bg-yellow-50" },
  { id: "PROCESSING", title: "В обработке", color: "border-blue-200 bg-blue-50" },
  { id: "SHIPPED", title: "Отправлен", color: "border-purple-200 bg-purple-50" },
  { id: "COMPLETED", title: "Выполнен", color: "border-green-200 bg-green-50" },
  { id: "CANCELLED", title: "Отменен", color: "border-red-200 bg-red-50" },
  { id: "REFUND_REQUESTED", title: "Запрошен возврат", color: "border-orange-200 bg-orange-50" },
  { id: "REFUNDED", title: "Возвращен", color: "border-indigo-200 bg-indigo-50" },
];

export function OrderKanbanBoard({ orders: initialOrders, storeId }: OrderKanbanBoardProps) {
  const [isMounted, setIsMounted] = useState(false);
  const [orders, setOrders] = useState(initialOrders);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  // Sync state with props if they change
  useEffect(() => {
    setOrders(initialOrders);
  }, [initialOrders]);

  if (!isMounted) {
    return (
      <div className="flex justify-center items-center py-20 text-gray-500">
        Загрузка доски...
      </div>
    );
  }

  const getOrdersByStatus = (status: string) => {
    return orders.filter((order) => order.status === status);
  };

  const onDragEnd = async (result: DropResult) => {
    const { destination, source, draggableId } = result;

    if (!destination) return;

    if (
      destination.droppableId === source.droppableId &&
      destination.index === source.index
    ) {
      return;
    }

    const newStatus = destination.droppableId;
    const orderId = draggableId;

    // Optimistic update
    const previousOrders = [...orders];
    setOrders(orders.map(order => 
      order.id === orderId ? { ...order, status: newStatus as any } : order
    ));

    try {
      const res = await updateOrderStatus(orderId, storeId, newStatus);
      if (res?.error) {
        toast.error(res.error);
        setOrders(previousOrders); // Revert on error
      } else {
        toast.success(`Статус заказа изменен`);
      }
    } catch (error) {
      toast.error("Произошла ошибка");
      setOrders(previousOrders); // Revert on error
    }
  };

  const handleRefund = async (orderId: string, approve: boolean) => {
    const previousOrders = [...orders];
    setOrders(orders.map(order => 
      order.id === orderId ? { ...order, status: approve ? "REFUNDED" as any : "COMPLETED" as any } : order
    ));

    try {
      const res = await processRefund(orderId, storeId, approve);
      if (res?.error) {
        toast.error(res.error);
        setOrders(previousOrders);
      } else {
        toast.success(res.success);
      }
    } catch (error) {
      toast.error("Произошла ошибка");
      setOrders(previousOrders);
    }
  };

  return (
    <DragDropContext onDragEnd={onDragEnd}>
      <div className="flex gap-6 overflow-x-auto pb-6 pt-2 h-full min-h-[70vh]">
        {COLUMNS.map((col) => (
          <div key={col.id} className="min-w-[320px] max-w-[320px] flex flex-col">
            <div className={`mb-3 p-3 rounded-lg border shadow-sm flex justify-between items-center ${col.color}`}>
              <h3 className="font-semibold text-gray-800">{col.title}</h3>
              <span className="bg-white/60 text-gray-600 text-xs py-1 px-2 rounded-full font-medium">
                {getOrdersByStatus(col.id).length}
              </span>
            </div>

            <Droppable droppableId={col.id}>
              {(provided, snapshot) => (
                <div
                  {...provided.droppableProps}
                  ref={provided.innerRef}
                  className={`flex-1 p-2 rounded-xl transition-colors ${
                    snapshot.isDraggingOver ? "bg-gray-100" : "bg-gray-50/50"
                  }`}
                >
                  {getOrdersByStatus(col.id).map((order, index) => (
                    <Draggable
                      key={order.id}
                      draggableId={order.id}
                      index={index}
                    >
                      {(provided, snapshot) => (
                        <div
                          ref={provided.innerRef}
                          {...provided.draggableProps}
                          {...provided.dragHandleProps}
                          className={`bg-white p-4 rounded-xl shadow-sm border border-gray-100 mb-3 cursor-grab active:cursor-grabbing hover:shadow-md transition-shadow ${
                            snapshot.isDragging ? "shadow-lg ring-2 ring-blue-500/20" : ""
                          }`}
                        >
                          <div className="flex justify-between items-start mb-2">
                            <div>
                              <div className="font-semibold text-gray-900 truncate max-w-[180px]">
                                {order.customerName}
                              </div>
                              <div className="text-xs text-gray-500">
                                {order.customerEmail}
                              </div>
                            </div>
                            <div className="font-bold text-gray-900">
                              ${order.totalPrice.toFixed(2)}
                            </div>
                          </div>

                          <div className="mt-3 text-sm text-gray-600 space-y-1">
                            {order.orderItems.map((item) => (
                              <div key={item.id} className="truncate text-xs">
                                <span className="font-medium text-gray-700">{item.quantity}x</span> {item.product.name}
                              </div>
                            ))}
                          </div>

                          <div className="mt-4 flex justify-between items-center text-xs text-gray-400 border-t pt-3">
                            <span>#{order.id.slice(0, 8).toUpperCase()}</span>
                            <span>{format(new Date(order.createdAt), "d MMM yyyy, HH:mm", { locale: ru })}</span>
                          </div>

                          {/* PDF Download Buttons */}
                          <div className="mt-2 flex gap-1.5">
                            <a
                              href={`/api/orders/${order.id}/pdf?type=invoice`}
                              target="_blank"
                              rel="noopener noreferrer"
                              onClick={(e) => e.stopPropagation()}
                              className="flex-1 text-center text-xs py-1 px-2 rounded bg-blue-50 text-blue-700 hover:bg-blue-100 border border-blue-200 transition-colors font-medium"
                            >
                              📄 Счёт
                            </a>
                            <a
                              href={`/api/orders/${order.id}/pdf?type=packing-slip`}
                              target="_blank"
                              rel="noopener noreferrer"
                              onClick={(e) => e.stopPropagation()}
                              className="flex-1 text-center text-xs py-1 px-2 rounded bg-green-50 text-green-700 hover:bg-green-100 border border-green-200 transition-colors font-medium"
                            >
                              📦 Накладная
                            </a>
                          </div>

                          {(order.status === "REFUND_REQUESTED" || order.status === "REFUNDED") && order.refundReason && (
                            <div className="mt-3 text-xs bg-orange-50 text-orange-800 p-2 rounded border border-orange-100">
                              <span className="font-semibold">Причина возврата:</span> {order.refundReason}
                            </div>
                          )}

                          {order.status === "REFUND_REQUESTED" && (
                            <div className="mt-3 flex gap-2">
                              <Button 
                                size="sm" 
                                variant="outline" 
                                className="w-full text-xs text-red-600 hover:text-red-700 hover:bg-red-50"
                                onClick={(e) => { e.stopPropagation(); handleRefund(order.id, false); }}
                              >
                                Отклонить
                              </Button>
                              <Button 
                                size="sm" 
                                className="w-full text-xs bg-green-600 hover:bg-green-700"
                                onClick={(e) => { e.stopPropagation(); handleRefund(order.id, true); }}
                              >
                                Одобрить
                              </Button>
                            </div>
                          )}
                        </div>
                      )}
                    </Draggable>
                  ))}
                  {provided.placeholder}
                </div>
              )}
            </Droppable>
          </div>
        ))}
      </div>
    </DragDropContext>
  );
}

