"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { OrderKanbanBoard } from "./kanban-board";
import { OrdersTable } from "./orders-table";
import { Button } from "@/components/ui/button";
import { LayoutList, LayoutGrid } from "lucide-react";
import { OrderWithItems } from "./types";

interface OrdersClientProps {
  initialOrders: OrderWithItems[];
  storeId: string;
  totalPages: number;
  currentPage: number;
}

export function OrdersClient({
  initialOrders,
  storeId,
  totalPages,
  currentPage: initialPage,
}: OrdersClientProps) {
  const [view, setView] = useState<"table" | "kanban">("table");
  const [isMounted, setIsMounted] = useState(false);
  const router = useRouter();

  useEffect(() => {
    setIsMounted(true);
    const savedView = localStorage.getItem("orders-view") as "table" | "kanban";
    if (savedView && ["table", "kanban"].includes(savedView)) {
      setView(savedView);
    }
  }, []);

  const toggleView = () => {
    const newView = view === "table" ? "kanban" : "table";
    setView(newView);
    localStorage.setItem("orders-view", newView);
  };

  const handleViewDetails = useCallback((orderId: string) => {
    router.push(`/dashboard/${storeId}/orders/${orderId}`);
  }, [storeId, router]);

  if (!isMounted) {
    return (
      <div className="flex justify-center items-center h-full min-h-screen">
        <div className="text-gray-500">Завантаження...</div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full min-h-screen">
      <div className="flex justify-end items-center mb-4">
        <div className="flex items-center border border-gray-200 rounded-lg overflow-hidden">
          <Button
            variant={view === "table" ? "default" : "ghost"}
            size="icon"
            onClick={toggleView}
            className="rounded-none"
            title="Таблиця"
          >
            <LayoutList className="h-4 w-4" />
          </Button>
          <Button
            variant={view === "kanban" ? "default" : "ghost"}
            size="icon"
            onClick={toggleView}
            className="rounded-none border-l border-gray-200"
            title="Канбан"
          >
            <LayoutGrid className="h-4 w-4" />
          </Button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden">
        {view === "table" ? (
          <OrdersTable
            orders={initialOrders}
            storeId={storeId}
            onViewDetails={handleViewDetails}
          />
        ) : (
          <OrderKanbanBoard orders={initialOrders} storeId={storeId} />
        )}
      </div>
    </div>
  );
}

"use client";

import { format } from "date-fns";
import { ru } from "date-fns/locale";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Eye, FileText } from "lucide-react";
import { OrderStatus } from "@prisma/client";
import { OrderWithItems } from "./types";

interface OrdersTableProps {
  orders: OrderWithItems[];
  storeId: string;
  onViewDetails: (orderId: string) => void;
}

const getStatusBadge = (status: OrderStatus) => {
  const variants: Record<OrderStatus, string> = {
    PENDING: "bg-yellow-100 text-yellow-800 border-yellow-200",
    PROCESSING: "bg-blue-100 text-blue-800 border-blue-200",
    SHIPPED: "bg-indigo-100 text-indigo-800 border-indigo-200",
    COMPLETED: "bg-green-100 text-green-800 border-green-200",
    CANCELLED: "bg-red-100 text-red-800 border-red-200",
    REFUND_REQUESTED: "bg-orange-100 text-orange-800 border-orange-200",
    REFUNDED: "bg-purple-100 text-purple-800 border-purple-200",
  };

  const labels: Record<OrderStatus, string> = {
    PENDING: "Новий",
    PROCESSING: "В обробці",
    SHIPPED: "Відправлено",
    COMPLETED: "Виконано",
    CANCELLED: "Скасовано",
    REFUND_REQUESTED: "Запит на поверхнення",
    REFUNDED: "Повернено",
  };

  return (
    <Badge className={`${variants[status] || variants.PENDING}`}>
      {labels[status] || status}
    </Badge>
  );
};

export function OrdersTable({ orders, storeId, onViewDetails }: OrdersTableProps) {
  if (orders.length === 0) {
    return (
      <div className="bg-white border border-gray-200 rounded-lg p-12 text-center text-gray-500 shadow-sm">
        <svg className="mx-auto h-12 w-12 text-gray-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
        </svg>
        Замовлень не знайдено
      </div>
    );
  }

  return (
    <div className="bg-white border border-gray-200 rounded-lg shadow-sm overflow-hidden">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead className="w-[120px]">№ Замовлення</TableHead>
            <TableHead>Покупець</TableHead>
            <TableHead className="text-center">Товарів</TableHead>
            <TableHead className="text-right">Сума</TableHead>
            <TableHead className="text-center">Статус</TableHead>
            <TableHead className="text-center">Дата</TableHead>
            <TableHead className="text-right">Дії</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {orders.map((order) => {
            const fraudStatus = (order as any).fraudStatus;
            const fraudScore = (order as any).fraudScore;
            const isBlocked = fraudStatus === 'BLOCKED';
            const isSuspicious = fraudStatus === 'SUSPICIOUS';
            const rowClass = isBlocked
              ? 'bg-red-50 hover:bg-red-100'
              : isSuspicious
              ? 'bg-yellow-50 hover:bg-yellow-100'
              : '';

          return (
            <TableRow key={order.id} className={rowClass}>
              <TableCell className="font-mono text-xs">
                #{order.id.slice(0, 8).toUpperCase()}
              </TableCell>
              <TableCell>
                <div className="font-medium">{order.customerName}</div>
                <div className="text-xs text-gray-500">{order.customerEmail}</div>
              </TableCell>
              <TableCell className="text-center">
                {order.orderItems.reduce((acc, item) => acc + item.quantity, 0)}
              </TableCell>
              <TableCell className="text-right font-medium">
                ${order.totalPrice.toFixed(2)}
              </TableCell>
              <TableCell className="text-center">
                <div className="flex flex-col items-center gap-1">
                  {getStatusBadge(order.status)}
                  {isBlocked && (
                    <Badge className="bg-red-600 text-white border-red-700 text-xs">
                      🚫 Заблок.
                    </Badge>
                  )}
                  {isSuspicious && (
                    <Badge className="bg-yellow-600 text-white border-yellow-700 text-xs">
                      ⚠️ Перевірити
                    </Badge>
                  )}
                  {fraudScore !== undefined && fraudScore !== null && fraudScore > 0 && !isBlocked && !isSuspicious && (
                    <Badge className="bg-gray-200 text-gray-700 border-gray-300 text-xs">
                      Score: {Math.round(fraudScore)}
                    </Badge>
                  )}
                </div>
              </TableCell>
                <TableCell className="text-center text-xs text-gray-500">
                  {format(new Date(order.createdAt), "dd.MM.yyyy HH:mm", { locale: ru })}
                </TableCell>
                <TableCell className="text-right">
                  <div className="flex justify-end gap-2">
                    <Button
                      variant="outline"
                      size="icon"
                      className="h-8 w-8"
                      onClick={() => onViewDetails(order.id)}
                    >
                      <Eye className="h-4 w-4" />
                    </Button>
                    <a
                      href={`/api/orders/${order.id}/pdf?type=invoice`}
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      <Button variant="outline" size="icon" className="h-8 w-8">
                        <FileText className="h-4 w-4" />
                      </Button>
                    </a>
                  </div>
                </TableCell>
              </TableRow>
            );
          })}
        </TableBody>
      </Table>
    </div>
  );
}

"use client";

import { useState } from "react";
import { createPage } from "@/actions/page";
import { toast } from "sonner";
import { useRouter } from "next/navigation";

export function CreatePageButton({ storeId }: { storeId: string }) {
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [name, setName] = useState("");
  const router = useRouter();

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    const res = await createPage(storeId, name);

    if (res.error) {
      toast.error(res.error);
    } else {
      toast.success(res.success);
      setIsOpen(false);
      setName("");
      // router.push(`/dashboard/${storeId}/builder/${res.pageId}`);
    }

    setIsLoading(false);
  };

  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
      >
        Создать страницу
      </button>

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          <div className="fixed inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsOpen(false)} />
          <div className="relative z-50 w-full max-w-md bg-white rounded-lg shadow-xl p-6">
            <h3 className="text-lg font-medium mb-4">Новая страница</h3>
            <form onSubmit={onSubmit}>
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Название
                </label>
                <input
                  type="text"
                  required
                  autoFocus
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  placeholder="Например, О нас"
                />
              </div>
              <div className="flex justify-end space-x-3">
                <button
                  type="button"
                  onClick={() => setIsOpen(false)}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50"
                  disabled={isLoading}
                >
                  Отмена
                </button>
                <button
                  type="submit"
                  disabled={isLoading}
                  className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-md hover:bg-blue-700 disabled:opacity-50"
                >
                  {isLoading ? "Создание..." : "Создать"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Trash2, Plus, Search } from "lucide-react";
import { addPriceListEntry, removePriceListEntry, updatePriceList } from "@/actions/price-list";
import { toast } from "sonner";
import Link from "next/link";
import { PriceListType } from "@prisma/client";
import Image from "next/image";

interface PriceListDetailClientProps {
  storeId: string;
  initialData: {
    id: string;
    name: string;
    type: PriceListType;
    value: number;
    isActive: boolean;
    entries: Array<{
      id: string;
      productId: string;
      customPrice: number;
      product: {
        id: string;
        name: string;
        price: number;
        imageUrl: string | null;
      }
    }>;
  };
  products: Array<{
    id: string;
    name: string;
    price: number;
    imageUrl: string | null;
  }>;
}

export function PriceListDetailClient({ storeId, initialData, products }: PriceListDetailClientProps) {
  const router = useRouter();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isActive, setIsActive] = useState(initialData.isActive);

  // Добавление товара
  const [selectedProductId, setSelectedProductId] = useState("");
  const [customPrice, setCustomPrice] = useState("");
  const [searchQuery, setSearchQuery] = useState("");

  const handleToggleActive = async () => {
    try {
      const newStatus = !isActive;
      setIsActive(newStatus);

      const result = await updatePriceList(storeId, initialData.id, {
        name: initialData.name,
        type: initialData.type,
        value: initialData.value,
        isActive: newStatus,
      });

      if (result.error) {
        setIsActive(!newStatus); // rollback
        toast.error(result.error);
        return;
      }
      toast.success(newStatus ? "Прайс-лист активирован" : "Прайс-лист отключен");
    } catch (error) {
      setIsActive(!isActive);
      toast.error("Произошла ошибка");
    }
  };

  const handleAddEntry = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProductId || !customPrice) return;

    setIsSubmitting(true);
    try {
      const result = await addPriceListEntry(storeId, initialData.id, {
        productId: selectedProductId,
        customPrice: parseFloat(customPrice),
      });

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success("Товар добавлен");
      setSelectedProductId("");
      setCustomPrice("");
      setSearchQuery("");
      router.refresh();
    } catch (error) {
      toast.error("Произошла ошибка");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRemoveEntry = async (entryId: string) => {
    try {
      const result = await removePriceListEntry(storeId, initialData.id, entryId);

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success("Товар удален");
      router.refresh();
    } catch (error) {
      toast.error("Произошла ошибка");
    }
  };

  // Фильтрация товаров для выпадающего списка (исключая уже добавленные)
  const availableProducts = products
    .filter(p => !initialData.entries.some(e => e.productId === p.id))
    .filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()));

  const selectedProductInfo = products.find(p => p.id === selectedProductId);

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Link href={`/dashboard/${storeId}/price-lists`}>
            <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-500">
              <ArrowLeft className="h-4 w-4" />
            </Button>
          </Link>
          <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-3">
              {initialData.name}
              <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                isActive ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-600'
              }`}>
                {isActive ? 'Активен' : 'Отключен'}
              </span>
            </h1>
            <p className="text-sm text-slate-500 mt-1">
              {initialData.type === "FIXED_PRICE" 
                ? "Фиксированные цены на выбранные товары" 
                : `Глобальная скидка ${initialData.value}%`}
            </p>
          </div>
        </div>

        <Button 
          variant={isActive ? "outline" : "default"} 
          onClick={handleToggleActive}
        >
          {isActive ? "Отключить прайс-лист" : "Активировать"}
        </Button>
      </div>

      {initialData.type === "FIXED_PRICE" && (
        <div className="bg-white p-6 rounded-xl border shadow-sm space-y-6">
          <h2 className="text-lg font-semibold text-slate-900">Добавить товар</h2>

          <form onSubmit={handleAddEntry} className="flex flex-col sm:flex-row gap-4 items-end">
            <div className="flex-1 w-full relative">
              <label className="block text-sm font-medium text-slate-700 mb-1.5">Поиск товара</label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <input
                  type="text"
                  placeholder="Начните вводить название..."
                  className="w-full pl-9 pr-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={searchQuery}
                  onChange={(e) => {
                    setSearchQuery(e.target.value);
                    if (selectedProductId) setSelectedProductId(""); // сброс при поиске
                  }}
                />
              </div>

              {searchQuery && !selectedProductId && availableProducts.length > 0 && (
                <div className="absolute z-10 w-full mt-1 bg-white border rounded-lg shadow-lg max-h-60 overflow-y-auto">
                  {availableProducts.map(product => (
                    <div
                      key={product.id}
                      className="px-4 py-2 hover:bg-slate-50 cursor-pointer flex items-center justify-between border-b last:border-0"
                      onClick={() => {
                        setSelectedProductId(product.id);
                        setSearchQuery(product.name);
                        setCustomPrice(product.price.toString()); // предлагаем текущую цену
                      }}
                    >
                      <span className="text-sm font-medium text-slate-900 truncate pr-4">{product.name}</span>
                      <span className="text-sm text-slate-500">${product.price.toFixed(2)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="w-full sm:w-32">
              <label className="block text-sm font-medium text-slate-700 mb-1.5">Новая цена</label>
              <input
                type="number"
                required
                min="0"
                step="0.01"
                className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={customPrice}
                onChange={(e) => setCustomPrice(e.target.value)}
                placeholder="0.00"
              />
            </div>

            <Button type="submit" disabled={!selectedProductId || !customPrice || isSubmitting} className="w-full sm:w-auto">
              <Plus className="w-4 h-4 mr-2" />
              Добавить
            </Button>
          </form>

          {selectedProductInfo && (
            <div className="text-sm text-slate-500 bg-slate-50 p-3 rounded-lg border flex items-center justify-between">
              <div className="flex items-center gap-3">
                {selectedProductInfo.imageUrl ? (
                  <div className="h-8 w-8 relative rounded overflow-hidden bg-white border">
                    <Image src={selectedProductInfo.imageUrl} alt="" fill className="object-cover" />
                  </div>
                ) : (
                  <div className="h-8 w-8 bg-slate-200 rounded" />
                )}
                <span>Стандартная цена: <strong className="text-slate-900">${selectedProductInfo.price.toFixed(2)}</strong></span>
              </div>
              {customPrice && (
                <span className="font-medium text-green-600">
                  Скидка: {(((selectedProductInfo.price - parseFloat(customPrice)) / selectedProductInfo.price) * 100).toFixed(0)}%
                </span>
              )}
            </div>
          )}

          <div className="mt-8">
            <h3 className="text-sm font-medium text-slate-900 mb-4 flex items-center justify-between border-b pb-2">
              Товары в прайс-листе ({initialData.entries.length})
            </h3>

            <div className="space-y-2">
              {initialData.entries.length === 0 ? (
                <div className="text-center py-8 text-slate-500 text-sm bg-slate-50 rounded-lg border border-dashed">
                  В этом прайс-листе пока нет товаров
                </div>
              ) : (
                initialData.entries.map((entry) => (
                  <div key={entry.id} className="flex items-center justify-between p-3 bg-white border rounded-lg hover:shadow-sm transition-shadow">
                    <div className="flex items-center gap-4">
                      {entry.product.imageUrl ? (
                         <div className="h-10 w-10 relative rounded overflow-hidden border">
                           <Image src={entry.product.imageUrl} alt="" fill className="object-cover" />
                         </div>
                      ) : (
                        <div className="h-10 w-10 bg-slate-100 rounded border" />
                      )}
                      <div>
                        <div className="text-sm font-medium text-slate-900 line-clamp-1">{entry.product.name}</div>
                        <div className="text-xs text-slate-500 line-through">${entry.product.price.toFixed(2)}</div>
                      </div>
                    </div>

                    <div className="flex items-center gap-6">
                      <div className="text-right">
                        <div className="text-sm font-bold text-green-600">${entry.customPrice.toFixed(2)}</div>
                        <div className="text-[10px] text-slate-400 font-medium uppercase tracking-wider">Опт. цена</div>
                      </div>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleRemoveEntry(entry.id)}
                        className="text-red-500 hover:text-red-700 hover:bg-red-50 px-2"
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {initialData.type === "PERCENTAGE_DISCOUNT" && (
         <div className="bg-blue-50 p-6 rounded-xl border border-blue-100 text-center">
            <h3 className="text-lg font-semibold text-blue-900 mb-2">Глобальная скидка</h3>
            <p className="text-blue-700 mb-4">
              Этот прайс-лист применяет фиксированную скидку <strong>{initialData.value}%</strong> ко всем товарам. 
              Вам не нужно добавлять товары вручную.
            </p>
         </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Plus, Trash2, Settings, Tag } from "lucide-react";
import { createPriceList, deletePriceList } from "@/actions/price-list";
import { toast } from "sonner";
import Link from "next/link";
import { PriceListType } from "@prisma/client";

interface PriceListWithCounts {
  id: string;
  storeId: string;
  name: string;
  type: PriceListType;
  value: number;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
  _count: {
    entries: number;
    customerGroups: number;
  };
}

interface PriceListsClientProps {
  storeId: string;
  initialData: PriceListWithCounts[];
}

export function PriceListsClient({ storeId, initialData }: PriceListsClientProps) {
  const router = useRouter();
  const [priceLists, setPriceLists] = useState<PriceListWithCounts[]>(initialData);
  const [isCreating, setIsCreating] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Форма
  const [name, setName] = useState("");
  const [type, setType] = useState<PriceListType>("FIXED_PRICE");
  const [value, setValue] = useState("0");

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;

    setIsSubmitting(true);
    try {
      const result = await createPriceList(storeId, {
        name,
        type,
        value: parseFloat(value) || 0,
        isActive: true,
      });

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success("Прайс-лист создан");
      setIsCreating(false);
      setName("");
      setValue("0");
      setType("FIXED_PRICE");
      router.refresh();
      // Мы не можем легко обновить локальный стейт с правильными count, 
      // поэтому полагаемся на refresh. Но для оптимистичного UI можно добавить фейковый
    } catch (error) {
      toast.error("Произошла ошибка");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Вы уверены? Это удалит все цены в этом прайс-листе.")) return;

    try {
      const result = await deletePriceList(storeId, id);

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success("Прайс-лист удален");
      setPriceLists(prev => prev.filter(p => p.id !== id));
      router.refresh();
    } catch (error) {
      toast.error("Произошла ошибка");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <Button onClick={() => setIsCreating(true)} disabled={isCreating}>
          <Plus className="w-4 h-4 mr-2" />
          Новый прайс-лист
        </Button>
      </div>

      {isCreating && (
        <form onSubmit={handleCreate} className="bg-white p-5 rounded-xl border shadow-sm flex flex-wrap gap-4 items-end">
          <div className="flex-1 min-w-[200px]">
            <label className="block text-sm font-medium text-slate-700 mb-1.5">Название</label>
            <input
              type="text"
              required
              className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Оптовые цены (Level 1)"
            />
          </div>
          <div className="w-48">
            <label className="block text-sm font-medium text-slate-700 mb-1.5">Тип</label>
            <select
              className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
              value={type}
              onChange={(e) => setType(e.target.value as PriceListType)}
            >
              <option value="FIXED_PRICE">Фиксированные цены</option>
              <option value="PERCENTAGE_DISCOUNT">Процентная скидка</option>
            </select>
          </div>
          {type === "PERCENTAGE_DISCOUNT" && (
            <div className="w-32">
              <label className="block text-sm font-medium text-slate-700 mb-1.5">Скидка (%)</label>
              <input
                type="number"
                required
                min="0"
                max="100"
                step="0.1"
                className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={value}
                onChange={(e) => setValue(e.target.value)}
              />
            </div>
          )}
          <div className="flex gap-2">
            <Button type="button" variant="outline" onClick={() => setIsCreating(false)}>
              Отмена
            </Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting ? "Создание..." : "Сохранить"}
            </Button>
          </div>
        </form>
      )}

      <div className="bg-white rounded-xl border shadow-sm overflow-hidden overflow-x-auto">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Прайс-лист</th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Тип</th>
              <th className="px-6 py-4 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider">Товаров</th>
              <th className="px-6 py-4 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider">Групп</th>
              <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Действия</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {initialData.map((list) => (
              <tr key={list.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center">
                    <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center mr-3">
                      <Tag className="h-4 w-4 text-blue-600" />
                    </div>
                    <div>
                      <div className="text-sm font-medium text-slate-900">{list.name}</div>
                      <div className="text-xs text-slate-500">
                        {list.isActive ? (
                          <span className="text-green-600 font-medium">Активен</span>
                        ) : (
                          <span className="text-slate-400">Отключен</span>
                        )}
                      </div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                    {list.type === "FIXED_PRICE" ? "Фиксированные цены" : `Скидка ${list.value}%`}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-center text-sm text-slate-500">
                  {list.type === "FIXED_PRICE" ? list._count.entries : "—"}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-center text-sm text-slate-500">
                  {list._count.customerGroups}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  <div className="flex justify-end items-center gap-2">
                    <Link href={`/dashboard/${storeId}/price-lists/${list.id}`}>
                      <Button variant="ghost" size="sm" className="text-blue-600 hover:text-blue-900 hover:bg-blue-50">
                        <Settings className="w-4 h-4 mr-1.5" />
                        Настроить
                      </Button>
                    </Link>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleDelete(list.id)}
                      className="text-red-600 hover:text-red-900 hover:bg-red-50 px-2"
                    >
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </td>
              </tr>
            ))}
            {initialData.length === 0 && !isCreating && (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center">
                  <Tag className="mx-auto h-12 w-12 text-slate-300 mb-3" />
                  <h3 className="text-sm font-medium text-slate-900">Нет прайс-листов</h3>
                  <p className="mt-1 text-sm text-slate-500">
                    Создайте первый прайс-лист для настройки B2B цен.
                  </p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { productSchema, ProductInput } from "@/lib/validations/product";
import { createProduct, updateProduct } from "@/actions/product";
import { Category } from "@prisma/client";
import { Button } from "@/components/ui/button";
import { Loader2, Plus, Trash } from "lucide-react";
import { ProductImageUploader, ImageItem } from "@/components/dashboard/product-image-uploader";
import { ProductTranslationTabs, TranslationsMap } from "@/components/dashboard/product-translation-tabs";
import { saveProductTranslation } from "@/actions/translations";
import { AIWritingToolbar } from "@/components/dashboard/ai-writing-toolbar";
import { SEOGenerator } from "@/components/dashboard/seo-generator";

interface ProductFormProps {
  initialData: any | null;
  categories: Category[];
  storeId: string;
}

// Функція для візуалізації ієрархії категорій з відступами
const flattenCategories = (categories: Category[], parentId: string | null = null, level: number = 0): { id: string; name: string; level: number }[] => {
  const result: { id: string; name: string; level: number }[] = [];

  categories
    .filter((c) => c.parentId === parentId)
    .forEach((category) => {
      const prefix = level > 0 ? " ".repeat((level - 1) * 2) + "└─ " : "";
      result.push({ id: category.id, name: `${prefix}${category.name}`, level });
      const children = flattenCategories(categories, category.id, level + 1);
      result.push(...children);
    });

  return result;
};

export const ProductForm = ({ initialData, categories, storeId }: ProductFormProps) => {
  const flatCategories = flattenCategories(categories);
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("basic");


  // Конвертируем images из initialData в формат ImageItem[]
  const initialImages: ImageItem[] = initialData?.images
    ? initialData.images.map((img: any, idx: number) => ({
        id: `img-${idx}-${Date.now()}`,
        url: typeof img === "string" ? img : img.url || "",
        alt: typeof img === "object" && img.alt ? img.alt : `Product image ${idx + 1}`,
      }))
    : [];

  const form = useForm<ProductInput>({
    resolver: zodResolver(productSchema) as any,
    defaultValues: initialData
      ? {
          ...initialData,
          price: Number(initialData.price),
          compareAtPrice: initialData.compareAtPrice ? Number(initialData.compareAtPrice) : undefined,
          stock: initialData.stock,
          attributes: initialData.attributes ? (Array.isArray(initialData.attributes) ? initialData.attributes : []) : [],
          variants: initialData.variants ? (Array.isArray(initialData.variants) ? initialData.variants : []) : [],
          tieredPricing: initialData.tieredPricing ? (Array.isArray(initialData.tieredPricing) ? initialData.tieredPricing : []) : [],
          images: initialData.images?.map((img: any) => typeof img === "string" ? img : img.url) || [],
        }
      : {
          name: "",
          description: "",
          price: 0,
          stock: 0,
          attributes: [],
          variants: [],
          tieredPricing: [],
          images: [],
          colors: [],
          tags: [],
        },
  });

  const { fields: attributeFields, append: appendAttribute, remove: removeAttribute } = useFieldArray({
    control: form.control,
    name: "attributes",
  });

  const { fields: variantFields, append: appendVariant, remove: removeVariant, replace: replaceVariants } = useFieldArray({
    control: form.control,
    name: "variants",
  });

  const { fields: tieredPricingFields, append: appendTieredPricing, remove: removeTieredPricing } = useFieldArray({
    control: form.control,
    name: "tieredPricing",
  });

  // Окремий стан для зобраень
  const [images, setImages] = useState<ImageItem[]>(initialImages);

  // Стан для мультимовних перекладів
  const [translations, setTranslations] = useState<TranslationsMap>({
    uk: { name: "", description: "", seoTitle: "", seoDescription: "" },
    en: { name: "", description: "", seoTitle: "", seoDescription: "" },
    pl: { name: "", description: "", seoTitle: "", seoDescription: "" },
  });

  // Ініціалізація перекладів з БД
  useEffect(() => {
    if (initialData?.translations) {
      const dbTranslations = initialData.translations as any[];
      const uk = dbTranslations.find((t) => t.locale === "uk") || {};
      const en = dbTranslations.find((t) => t.locale === "en") || {};
      const pl = dbTranslations.find((t) => t.locale === "pl") || {};

      setTranslations({
        uk: {
          name: uk.name || "",
          description: uk.description || "",
          seoTitle: uk.seoTitle || "",
          seoDescription: uk.seoDescription || "",
        },
        en: {
          name: en.name || "",
          description: en.description || "",
          seoTitle: en.seoTitle || "",
          seoDescription: en.seoDescription || "",
        },
        pl: {
          name: pl.name || "",
          description: pl.description || "",
          seoTitle: pl.seoTitle || "",
          seoDescription: pl.seoDescription || "",
        },
      });
    }
  }, [initialData?.translations]);

  const onSubmit = async (data: ProductInput) => {
    try {
      setIsLoading(true);
      // Конвертуємо ImageItem[] в масив URL для Prisma
      const imagesData = images.map((img) => img.url);

      const payload = {
        ...data,
        images: imagesData,
      };

      let productId = initialData?.id;

      if (initialData) {
        await updateProduct(initialData.id, storeId, payload);
        productId = initialData.id;
      } else {
        const result = await createProduct(storeId, payload);
        // Отримуємо ID щойно створеного продукту
        if ('id' in result && result.id) {
          productId = result.id;
        }
      }

      // Зберігаємо переклади для EN та PL
      if (productId) {
        // Зберігаємо англійський переклад
        if (translations.en.name || translations.en.description) {
          await saveProductTranslation(productId, "en", {
            name: translations.en.name,
            description: translations.en.description || null,
            seoTitle: translations.en.seoTitle || null,
            seoDescription: translations.en.seoDescription || null,
          });
        }

        // Зберігаємо польський переклад
        if (translations.pl.name || translations.pl.description) {
          await saveProductTranslation(productId, "pl", {
            name: translations.pl.name,
            description: translations.pl.description || null,
            seoTitle: translations.pl.seoTitle || null,
            seoDescription: translations.pl.seoDescription || null,
          });
        }
      }

      router.push(`/dashboard/${storeId}/products`);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const generateVariants = () => {
    const attrs = form.getValues("attributes") || [];
    if (attrs.length === 0) return;

    const arrays = attrs.map((attr) => attr.values);

    // Cartesian product
    const cartesian = (...a: any[][]) =>
      a.reduce((a, b) => a.flatMap((d) => b.map((e) => [d, e].flat())));
    const combinations = attrs.length > 1 ? cartesian(...arrays) : arrays[0].map((v) => [v]);

    const newVariants = combinations.map((combo) => {
      const optionsRecord: Record<string, string> = {};
      attrs.forEach((attr, idx) => {
        optionsRecord[attr.name] = Array.isArray(combo) ? combo[idx] : combo;
      });
      // Створюємо назву варіації
      const name = Object.values(optionsRecord).join(" / ");
      return {
        id: undefined,
        name: name,
        sku: "",
        price: form.getValues("price"),
        stock: 0,
        options: optionsRecord,
      };
    });

    replaceVariants(newVariants);
  };

  // Обробник змін перекладів
  const handleTranslationsChange = (updatedTranslations: Partial<TranslationsMap>) => {
    setTranslations((prev) => ({
      ...prev,
      ...updatedTranslations,
    }));
  };

  return (
    <div className="bg-white shadow-sm rounded-lg border p-6">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">{initialData ? "Редактировать товар" : "Новый товар"}</h2>
        <Button variant="outline" onClick={() => router.push(`/dashboard/${storeId}/products`)}>
          Отмена
        </Button>
      </div>

      <div className="flex space-x-4 mb-6 border-b">
        {["basic", "attributes", "variants", "tieredPricing"].map((tab) => (
          <button
            key={tab}
            onClick={(e) => {
              e.preventDefault();
              setActiveTab(tab);
            }}
            className={`pb-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === tab
                ? "border-blue-500 text-blue-600"
                : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
            }`}
          >
            {tab === "basic" && "Основное"}
            {tab === "attributes" && "Атрибуты"}
            {tab === "variants" && "Вариации"}
            {tab === "tieredPricing" && "Оптовые цены"}
          </button>
        ))}
      </div>

      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
        {activeTab === "basic" && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Название</label>
              <input
                {...form.register("name")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
              />
            </div>
            <div>
              <div className="flex items-center justify-between mb-1">
                <label className="block text-sm font-medium text-gray-700">Описание</label>
                <AIWritingToolbar
                  storeId={storeId}
                  currentText={form.watch("description") || ""}
                  onGenerate={(text) => form.setValue("description", text)}
                  onRewrite={(text) => form.setValue("description", text)}
                  disabled={isLoading}
                />
              </div>
              <textarea
                {...form.register("description")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                rows={4}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Цена</label>
                <input
                  type="number"
                  step="0.01"
                  {...form.register("price")}
                  className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Старая цена</label>
                <input
                  type="number"
                  step="0.01"
                  {...form.register("compareAtPrice")}
                  className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Остаток</label>
              <input
                type="number"
                {...form.register("stock")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
              />
            </div>

            {/* Product Image Uploader */}
            <ProductImageUploader images={images} onChange={setImages} storeId={storeId} />

            {/* SEO Generator Section */}
            <div className="border-t pt-4 mt-4">
              <div className="flex items-center justify-between mb-2">
                <h3 className="text-sm font-medium text-gray-700">SEO (Meta теги)</h3>
                <SEOGenerator
                  storeId={storeId}
                  title={form.watch("name") || ""}
                  content={form.watch("description") || ""}
                  onGenerate={({ seoTitle, seoDescription, tags }) => {
                    form.setValue("seoTitle", seoTitle);
                    form.setValue("seoDescription", seoDescription);
                    if (tags) {
                      form.setValue("tags", tags.split(",").map((t: string) => t.trim()));
                    }
                  }}
                  disabled={isLoading}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700">SEO Title</label>
                  <input
                    {...form.register("seoTitle")}
                    className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700">SEO Description</label>
                  <input
                    {...form.register("seoDescription")}
                    className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                  />
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Категории</label>
              <div className="flex gap-2 mb-2">
                <select className="flex-1 rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border bg-white">
                  <option value="">Выберите категорию...</option>
                  {flatCategories.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.name}
                    </option>
                  ))}
                </select>
                <Button type="button" variant="outline" className="flex items-center gap-1">
                  <Plus className="w-4 h-4" /> Добавить
                </Button>
              </div>
              <div className="flex flex-wrap gap-2 mt-2">
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                  Основная категория
                  <button
                    type="button"
                    className="flex-shrink-0 ml-1.5 h-4 w-4 rounded-full inline-flex items-center justify-center text-blue-400 hover:bg-blue-200 hover:text-blue-500 focus:outline-none focus:bg-blue-500 focus:text-white"
                  >
                    <span className="sr-only">Remove category</span>
                    <svg
                      className="h-2 w-2"
                      stroke="currentColor"
                      fill="none"
                      viewBox="0 0 8 8"
                    >
                      <path strokeLinecap="round" strokeWidth="1.5" d="M1 1l6 6m0-6L1 7" />
                    </svg>
                  </button>
                </span>
              </div>
            </div>
          </div>
        )}

        {activeTab === "attributes" && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-medium">Атрибуты товара (например: Цвет, Размер)</h3>
              <Button
                type="button"
                variant="outline"
                onClick={() => appendAttribute({ name: "", values: [""] })}
              >
                <Plus className="mr-2 h-4 w-4" /> Добавить атрибут
              </Button>
            </div>

            {attributeFields.map((field, index) => (
              <div key={field.id} className="border p-4 rounded-md space-y-4">
                <div className="flex justify-between items-center">
                  <input
                    {...form.register(`attributes.${index}.name`)}
                    placeholder="Название атрибута (например: Размер)"
                    className="block w-1/3 rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                  />
                  <Button type="button" variant="ghost" onClick={() => removeAttribute(index)}>
                    <Trash className="h-4 w-4 text-red-500" />
                  </Button>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Значения (через запятую)
                  </label>
                  <input
                    defaultValue={form.getValues(`attributes.${index}.values`).join(", ")}
                    onChange={(e) => {
                      const values = e.target.value
                        .split(",")
                        .map((v) => v.trim())
                        .filter(Boolean);
                      form.setValue(`attributes.${index}.values`, values);
