                            />
                          </td>
                          <td
                            className="px-6 py-4 text-sm text-gray-900 max-w-xs truncate"
                            title={optionsText || "Без опций"}
                          >
                            {optionsText || "Без опций"}
                          </td>
                          <td className="px-6 py-4">
                            <input
                              type="number"
                              step="0.01"
                              {...form.register(`variants.${index}.price`)}
                              className="w-24 rounded-md border-gray-300 shadow-sm p-1 border"
                            />
                          </td>
                          <td className="px-6 py-4">
                            <input
                              type="number"
                              {...form.register(`variants.${index}.stock`)}
                              className="w-24 rounded-md border-gray-300 shadow-sm p-1 border"
                            />
                          </td>
                          <td className="px-6 py-4">
                            <input
                              {...form.register(`variants.${index}.sku`)}
                              className="w-full rounded-md border-gray-300 shadow-sm p-1 border"
                            />
                          </td>
                          <td className="px-6 py-4 text-right">
                            <button
                              type="button"
                              onClick={() => removeVariant(index)}
                              className="text-red-500 hover:text-red-700"
                            >
                              <Trash className="h-4 w-4" />
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {activeTab === "tieredPricing" && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-medium">Оптовые цены (скидки от количества)</h3>
              <Button
                type="button"
                variant="outline"
                onClick={() =>
                  appendTieredPricing({ minQuantity: 2, price: form.getValues("price") || 0 })
                }
              >
                <Plus className="mr-2 h-4 w-4" /> Добавить уровень цен
