                            {...form.register(`tieredPricing.${index}.price` as const)}
                            className="w-full rounded-md border-gray-300 shadow-sm p-2 border"
                          />
                          {form.formState.errors.tieredPricing?.[index]?.price && (
                            <span className="text-xs text-red-500">
                              {form.formState.errors.tieredPricing[index]?.price?.message}
                            </span>
                          )}
                        </td>
                        <td className="px-6 py-4 text-right">
                          <button
                            type="button"
                            onClick={() => removeTieredPricing(index)}
                            className="text-red-500 hover:text-red-700"
                          >
                            <Trash className="h-4 w-4" />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* Мультимовні вкладки */}
        <div className="pt-6 mt-6 border-t border-gray-200">
          <ProductTranslationTabs
            storeId={storeId}
            productId={initialData?.id}
            initialTranslations={translations}
            baseName={form.getValues("name") || ""}
            baseDescription={form.getValues("description") || ""}
            baseSeoTitle={form.getValues("seoTitle") || ""}
            baseSeoDescription={form.getValues("seoDescription") || ""}
            onChange={handleTranslationsChange}
          />
        </div>

        <div className="pt-5 border-t">
          <Button
            type="submit"
            disabled={isLoading}
            className="bg-blue-600 hover:bg-blue-700 text-white"
          >
            {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {initialData ? "Сохранить изменения" : "Создать товар"}
          </Button>
        </div>
      </form>
    </div>
  );
};

"use client";

import { useState, useRef } from "react";
import type { Product as PrismaProduct } from "@prisma/client";
import { updateProductInline, duplicateProductAction, generateSeoAction, importProducts } from "@/actions/product";
import { useRouter } from "next/navigation";
import { LayoutGrid, List as ListIcon, MoreVertical, Copy, Sparkles, Edit, Archive, ArchiveRestore, AlertCircle, Star, Plus, Download, Upload } from "lucide-react";
import { motion } from "framer-motion";
import Papa from "papaparse";
import { InlineEdit } from "@/components/ui/inline-edit";

type Product = PrismaProduct & {
  stock: number;
  images: string[];
  colors: string[];
  tags: string[];
  seoTitle: string | null;
  seoDescription: string | null;
  compareAtPrice?: number | null;
  isDraft: boolean;
};

type ProductStatus = "active" | "draft" | "archived";

function getProductStatus(product: Product): ProductStatus {
  if (product.isArchived) return "archived";
  if (product.isDraft) return "draft";
  return "active";
}

interface ProductsClientProps {
  data: Product[];
  storeId: string;
}

export function ProductsClient({ data, storeId }: ProductsClientProps) {
  const router = useRouter();
  const [view, setView] = useState<"list" | "grid">("list");
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editPrice, setEditPrice] = useState<number>(0);
  const [editStock, setEditStock] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);
  const [openDropdownId, setOpenDropdownId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleExportCSV = () => {
    const csvData = data.map((product) => ({
      ID: product.id,
      Название: product.name,
      Описание: product.description || "",
      Цена: product.price,
      "Старая цена": product.compareAtPrice || "",
      Остаток: product.stock,
      URL_изображения: product.imageUrl || "",
      Категория_ID: product.categoryId,
      Магазин_ID: product.storeId,
    }));

    const csv = Papa.unparse(csvData);
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `products_export_${storeId}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: async (results) => {
        try {
          const parsedData = results.data as any[];
          const formattedData = parsedData.map((row) => ({
            name: row["Название"],
            description: row["Описание"],
            price: parseFloat(row["Цена"]),
            compareAtPrice: row["Старая цена"] ? parseFloat(row["Старая цена"]) : null,
            stock: parseInt(row["Остаток"], 10),
            imageUrl: row["URL_изображения"],
            categoryId: row["Категория_ID"],
          }));

          await importProducts(storeId, formattedData);
          router.refresh();
        } catch (error) {
          console.error("Ошибка при импорте:", error);
          alert("Произошла ошибка при импорте. Проверьте формат файла.");
        } finally {
          setIsLoading(false);
          if (fileInputRef.current) fileInputRef.current.value = "";
        }
      },
      error: (error) => {
        console.error("Ошибка парсинга CSV:", error);
        alert("Ошибка при чтении файла.");
        setIsLoading(false);
      }
    });
  };

  const handleInlineEditStart = (product: Product) => {
    setEditingId(product.id);
    setEditPrice(product.price);
    setEditStock(product.stock);
  };

  const handleInlineEditSave = async (id: string) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { price: editPrice, stock: editStock });
      setEditingId(null);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleStatusChange = async (id: string, status: ProductStatus) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { 
        isArchived: status === "archived",
        isDraft: status === "draft"
      });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  const handleToggleArchive = async (id: string, isArchived: boolean) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { isArchived: !isArchived });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  const handleToggleFeatured = async (id: string, isFeatured: boolean) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { isFeatured: !isFeatured });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDuplicate = async (id: string) => {
    try {
      setIsLoading(true);
      await duplicateProductAction(id, storeId);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  const handleGenerateSeo = async (id: string) => {
    try {
      setIsLoading(true);
      await generateSeoAction(id, storeId);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  return (
    <>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Товары</h1>
          <p className="text-gray-500 mt-2">
            Управляйте товарами вашего магазина для витрины.
          </p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex border border-gray-300 rounded-md overflow-hidden mr-2">
            <button
              onClick={handleExportCSV}
              className="p-2 bg-white hover:bg-gray-50 flex items-center gap-1 border-r border-gray-300"
              title="Экспорт в CSV"
              disabled={isLoading}
            >
              <Download className="h-4 w-4 text-gray-600" />
              <span className="text-sm font-medium text-gray-700 hidden sm:inline-block">Экспорт</span>
            </button>
            <button
              onClick={() => fileInputRef.current?.click()}
              className="p-2 bg-white hover:bg-gray-50 flex items-center gap-1"
              title="Импорт из CSV"
              disabled={isLoading}
            >
              <Upload className="h-4 w-4 text-gray-600" />
              <span className="text-sm font-medium text-gray-700 hidden sm:inline-block">Импорт</span>
            </button>
            <input
              type="file"
              accept=".csv"
              ref={fileInputRef}
              onChange={handleImportCSV}
              className="hidden"
            />
          </div>
          <div className="flex border border-gray-300 rounded-md overflow-hidden">
            <button
              onClick={() => setView("list")}
              className={`p-2 ${view === "list" ? "bg-gray-100" : "bg-white hover:bg-gray-50"}`}
              title="Список"
            >
              <ListIcon className="h-5 w-5 text-gray-600" />
            </button>
            <button
              onClick={() => setView("grid")}
              className={`p-2 border-l border-gray-300 ${view === "grid" ? "bg-gray-100" : "bg-white hover:bg-gray-50"}`}
              title="Сетка"
            >
              <LayoutGrid className="h-5 w-5 text-gray-600" />
            </button>
          </div>
          <button
            onClick={() => router.push(`/dashboard/${storeId}/products/new`)}
            className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
          >
            <Plus className="-ml-1 mr-2 h-5 w-5" />
            Добавить товар
          </button>
        </div>
      </div>

      {data.length === 0 ? (
        <div className="bg-white border border-gray-200 rounded-lg p-12 text-center text-gray-500 shadow-sm">
          <svg className="mx-auto h-12 w-12 text-gray-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
          </svg>
          У вас пока нет добавленных товаров.
        </div>
      ) : view === "list" ? (
        <div className="bg-white shadow-sm border border-gray-200 rounded-lg overflow-hidden overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Товар</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Цена</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Остаток</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Статус</th>
                <th scope="col" className="relative px-6 py-3"><span className="sr-only">Действия</span></th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {data.map((product) => (
                <tr key={product.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <div className="h-10 w-10 flex-shrink-0 relative rounded-md overflow-hidden bg-gray-100">
                        {product.imageUrl ? (
                          <img src={product.imageUrl} alt={product.name} className="object-cover h-full w-full" />
                        ) : (
                          <svg className="h-6 w-6 text-gray-400 m-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                          </svg>
                        )}
                      </div>
                      <div className="ml-4 cursor-pointer" onClick={() => router.push(`/dashboard/${storeId}/products/${product.id}`)}>
                        <div className="text-sm font-medium text-gray-900 hover:text-blue-600">{product.name}</div>
                        <div className="text-sm text-gray-500 truncate max-w-[200px]">{product.seoTitle || product.description}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <InlineEdit
                      value={product.price}
                      type="price"
                      onSave={async (val) => {
                        setEditPrice(val);
                        setEditStock(product.stock);
                        await handleInlineEditSave(product.id);
                      }}
                      format={(val) => `$${val.toFixed(2)}`}
                    />
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <InlineEdit
                      value={product.stock}
                      type="stock"
                      onSave={async (val) => {
                        setEditStock(val);
                        setEditPrice(product.price);
                        await handleInlineEditSave(product.id);
                      }}
                    />
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <select
                      value={getProductStatus(product)}
                      onChange={(e) => handleStatusChange(product.id, e.target.value as ProductStatus)}
                      disabled={isLoading}
                      className={`text-xs font-semibold rounded-full px-2 py-1 border-0 bg-transparent cursor-pointer hover:opacity-80 focus:ring-2 focus:ring-blue-500 outline-none
                        ${getProductStatus(product) === 'active' ? 'bg-green-100 text-green-800' : ''}
                        ${getProductStatus(product) === 'draft' ? 'bg-yellow-100 text-yellow-800' : ''}
                        ${getProductStatus(product) === 'archived' ? 'bg-gray-100 text-gray-800' : ''}
                      `}
                    >
                      <option value="active" className="bg-white text-gray-900">Активен</option>
                      <option value="draft" className="bg-white text-gray-900">Черновик</option>
                      <option value="archived" className="bg-white text-gray-900">В архиве</option>
                    </select>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium relative">
                    <button
                      onClick={() => handleToggleFeatured(product.id, product.isFeatured)}
                      className={`mr-3 p-1 rounded-full transition-colors ${
                        product.isFeatured ? "text-yellow-400 hover:text-yellow-500 bg-yellow-50" : "text-gray-300 hover:text-yellow-400 hover:bg-gray-50"
                      }`}
                      title={product.isFeatured ? "Убрать из избранного" : "В избранное"}
                    >
                      <Star className={`h-5 w-5 ${product.isFeatured ? "fill-current" : ""}`} />
                    </button>
                    <button
                      onClick={() => setOpenDropdownId(openDropdownId === product.id ? null : product.id)}
                      className="text-gray-400 hover:text-gray-600 p-1"
                    >
                      <MoreVertical className="h-5 w-5" />
                    </button>
                    {openDropdownId === product.id && (
                      <div className="absolute right-8 top-10 w-48 bg-white rounded-md shadow-lg z-10 border border-gray-200 py-1">
                        <button
                          onClick={() => { router.push(`/dashboard/${storeId}/products/${product.id}`); setOpenDropdownId(null); }}
                          className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 flex items-center gap-2"
                        >
                          <Edit className="h-4 w-4" /> Редактировать
                        </button>
                        <button
                          onClick={() => handleDuplicate(product.id)}
                          disabled={isLoading}
                          className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 flex items-center gap-2"
                        >
                          <Copy className="h-4 w-4" /> Дублировать
                        </button>
                        <button
                          onClick={() => handleGenerateSeo(product.id)}
                          disabled={isLoading}
                          className="w-full text-left px-4 py-2 text-sm text-blue-600 hover:bg-gray-100 flex items-center gap-2"
                        >
                          <Sparkles className="h-4 w-4" /> AI SEO (Beta)
                        </button>
                        <button
                          onClick={() => handleStatusChange(product.id, product.isArchived ? "active" : "archived")}
                          disabled={isLoading}
                          className="w-full text-left px-4 py-2 text-sm text-orange-600 hover:bg-gray-100 flex items-center gap-2"
                        >
                          {product.isArchived ? <><ArchiveRestore className="h-4 w-4" /> Восстановить</> : <><Archive className="h-4 w-4" /> В архив</>}
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <motion.div 
          className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6"
          initial="hidden"
          animate="visible"
          variants={{
            hidden: { opacity: 0 },
            visible: {
              opacity: 1,
              transition: {
                staggerChildren: 0.1
              }
            }
          }}
        >
          {data.map((product) => (
            <motion.div 
              key={product.id} 
              className="bg-white border border-gray-200 rounded-xl overflow-hidden shadow-sm hover:shadow-lg transition-all duration-300 relative group flex flex-col"
              variants={{
                hidden: { opacity: 0, y: 20 },
                visible: { opacity: 1, y: 0 }
              }}
            >
              <div className="aspect-w-1 aspect-h-1 w-full bg-gray-50 overflow-hidden relative h-56 cursor-pointer" onClick={() => router.push(`/dashboard/${storeId}/products/${product.id}`)}>
                {product.imageUrl ? (
                  <img src={product.imageUrl} alt={product.name} className="object-cover object-center w-full h-full group-hover:scale-105 transition-transform duration-500" />
                ) : (
                  <div className="flex items-center justify-center h-full w-full">
                    <svg className="h-12 w-12 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                  </div>
                )}
                <div className="absolute top-3 right-3 flex flex-col gap-2 items-end">
                   {product.isArchived && (
                     <span className="px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md bg-gray-900/80 text-white backdrop-blur-sm">
                       Архив
                     </span>
                   )}
                   {!product.isArchived && (
                     <span className="px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md bg-emerald-500/90 text-white backdrop-blur-sm">
                       Активен
                     </span>
                   )}
                   {product.isFeatured && (
                     <span 
                       onClick={(e) => { e.stopPropagation(); handleToggleFeatured(product.id, product.isFeatured); }}
                       className="flex items-center gap-1 px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md bg-yellow-500/90 hover:bg-yellow-600/90 text-white backdrop-blur-sm shadow-sm cursor-pointer transition-colors"
                     >
                       <Star className="h-3 w-3 fill-current" /> Featured
                     </span>
                   )}
                   {!product.isFeatured && (
                     <span 
                       onClick={(e) => { e.stopPropagation(); handleToggleFeatured(product.id, product.isFeatured); }}
                       className="flex items-center justify-center w-6 h-6 rounded-md bg-white/50 hover:bg-yellow-100 text-gray-400 hover:text-yellow-500 backdrop-blur-sm shadow-sm cursor-pointer transition-all opacity-0 group-hover:opacity-100"
                       title="В избранное"
                     >
                       <Star className="h-4 w-4" />
                     </span>
                   )}
                </div>

                {product.stock < 5 && product.stock > 0 && (
                   <div className="absolute bottom-3 left-3">
                     <span className="flex items-center gap-1 px-2 py-1 text-xs font-semibold rounded-md bg-orange-100 text-orange-700 border border-orange-200 shadow-sm">
                       <AlertCircle className="h-3.5 w-3.5" /> Мало: {product.stock} шт
                     </span>
                   </div>
                )}
                {product.stock === 0 && (
                   <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] flex items-center justify-center">
                     <span className="px-3 py-1.5 text-sm font-bold uppercase tracking-wider rounded-lg bg-red-500 text-white shadow-lg">
                       Нет в наличии
                     </span>
                   </div>
                )}
              </div>
              <div className="p-5 flex-1 flex flex-col">
                <h3 className="text-base font-semibold text-gray-900 line-clamp-2 hover:text-blue-600 transition-colors cursor-pointer" title={product.name} onClick={() => router.push(`/dashboard/${storeId}/products/${product.id}`)}>{product.name}</h3>

                <div className="mt-3 flex items-end justify-between flex-1">
                  <div>
                    {editingId === product.id ? (
                       <div className="flex flex-col gap-1">
                         <span className="text-xs text-gray-500">Цена</span>
                         <input
                           type="number"
                           className="w-24 px-2 py-1 text-sm border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                           value={editPrice}
                           onChange={(e) => setEditPrice(Number(e.target.value))}
                         />
                       </div>
                    ) : (
                      <div className="flex flex-col cursor-pointer hover:bg-gray-50 rounded-md p-1 -ml-1 transition-colors" onClick={() => handleInlineEditStart(product)}>
                        <div className="flex items-baseline gap-2">
                          <span className="text-lg font-bold text-gray-900">${product.price.toFixed(2)}</span>
                          {product.compareAtPrice && product.compareAtPrice > product.price && (
                            <span className="text-xs font-medium text-gray-400 line-through">${product.compareAtPrice.toFixed(2)}</span>
                          )}
                        </div>
                      </div>
                    )}
                  </div>

                  <div>
                    {editingId === product.id ? (
                       <div className="flex flex-col gap-1">
                          <span className="text-xs text-gray-500">Остаток</span>
                          <input
                            type="number"
                            className="w-20 px-2 py-1 text-sm border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                            value={editStock}
                            onChange={(e) => setEditStock(Number(e.target.value))}
                          />
                       </div>
                    ) : (
                      <div className="flex flex-col items-end cursor-pointer hover:bg-gray-50 rounded-md p-1 -mr-1 transition-colors" onClick={() => handleInlineEditStart(product)}>
                        <span className="text-xs text-gray-500">На складе</span>
                        <span className="text-sm font-medium text-gray-700">{product.stock} шт</span>
                      </div>
                    )}
                  </div>
                </div>

                {editingId === product.id && (
                  <div className="mt-4 flex gap-2">
                    <button onClick={() => handleInlineEditSave(product.id)} className="flex-1 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium px-3 py-1.5 rounded-md transition-colors shadow-sm">Сохранить</button>
                    <button onClick={() => setEditingId(null)} className="flex-1 bg-white border border-gray-300 hover:bg-gray-50 text-gray-700 text-sm font-medium px-3 py-1.5 rounded-md transition-colors shadow-sm">Отмена</button>
                  </div>
                )}

                <div className="mt-5 pt-4 border-t border-gray-100 flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                   <button onClick={() => router.push(`/dashboard/${storeId}/products/${product.id}`)} className="text-sm text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1">
                     <Edit className="h-4 w-4" /> Редактировать
                   </button>
                   <div className="relative">
                     <button onClick={() => setOpenDropdownId(openDropdownId === product.id ? null : product.id)} className="text-gray-400 hover:text-gray-900 p-1.5 hover:bg-gray-100 rounded-full transition-colors">
                        <MoreVertical className="h-5 w-5" />
                     </button>
                     {openDropdownId === product.id && (
                      <div className="absolute right-0 bottom-full mb-2 w-48 bg-white rounded-xl shadow-xl z-20 border border-gray-100 py-1 overflow-hidden">
                        <button onClick={() => { router.push(`/dashboard/${storeId}/products/${product.id}`); setOpenDropdownId(null); }} className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-2">
                          <Edit className="h-4 w-4 text-gray-400" /> Редактировать
                        </button>
                        <button onClick={() => handleDuplicate(product.id)} className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-2">
                          <Copy className="h-4 w-4 text-gray-400" /> Дублировать
                        </button>
                        <button onClick={() => handleGenerateSeo(product.id)} className="w-full text-left px-4 py-2.5 text-sm text-blue-600 hover:bg-blue-50 flex items-center gap-2 font-medium">
                          <Sparkles className="h-4 w-4 text-blue-500" /> AI Оптимизация
                        </button>
                        <div className="h-px bg-gray-100 my-1"></div>
                        <button onClick={() => handleStatusChange(product.id, product.isArchived ? "active" : "archived")} className="w-full text-left px-4 py-2.5 text-sm text-amber-600 hover:bg-amber-50 flex items-center gap-2">
                          {product.isArchived ? <><ArchiveRestore className="h-4 w-4" /> Восстановить</> : <><Archive className="h-4 w-4" /> В архив</>}
                        </button>
                      </div>
                     )}
                   </div>
                </div>
              </div>
            </motion.div>
          ))}
        </motion.div>
      )}
    </>
  );
}

"use client";

import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";
import { updateReturnStatus } from "@/actions/returns";
import { toast } from "sonner";
import {
  RotateCcw,
  CheckCircle,
  XCircle,
  Clock,
  CreditCard,
  ChevronDown,
  ChevronUp,
  Filter,
} from "lucide-react";

// ─── Типы ─────────────────────────────────────────────────────────────────────

interface ReturnItem {
  id: string;
  orderItemId: string;
  quantity: number;
  reason: string | null;
}

interface ReturnRequest {
  id: string;
  orderId: string;
  storeId: string;
  status: "PENDING" | "APPROVED" | "REJECTED" | "REFUNDED";
  reason: string;
  staffNote: string | null;
  refundAmount: number | null;
  refundMethod: "ORIGINAL_PAYMENT" | "STORE_CREDIT" | "BANK_TRANSFER";
  createdAt: Date;
  order: {
    customerName: string;
    customerEmail: string;
    totalPrice: number;
    createdAt: Date;
  };
  items: ReturnItem[];
}

interface ReturnsStats {
  pending: number;
  approved: number;
  rejected: number;
  refunded: number;
  totalRefundAmount: number;
}

interface ReturnsClientProps {
  returnsList: ReturnRequest[];
  stats: ReturnsStats;
  storeId: string;
  currentStatus?: string;
}

// ─── Утилиты ──────────────────────────────────────────────────────────────────

const STATUS_LABELS: Record<string, string> = {
  PENDING: "Ожидает",
  APPROVED: "Одобрен",
  REJECTED: "Отклонён",
  REFUNDED: "Возвращён",
};

const REFUND_METHOD_LABELS: Record<string, string> = {
  ORIGINAL_PAYMENT: "Исходный способ оплаты",
  STORE_CREDIT: "Кредит магазина",
  BANK_TRANSFER: "Банковский перевод",
};

const STATUS_COLORS: Record<string, string> = {
  PENDING: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400",
  APPROVED: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
  REJECTED: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400",
  REFUNDED: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
};

// ─── Карточка статистики ───────────────────────────────────────────────────────

function StatCard({
  label,
  value,
  icon: Icon,
  color,
}: {
  label: string;
  value: string | number;
  icon: React.ElementType;
  color: string;
}) {
  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl p-5 border border-slate-200 dark:border-slate-700">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-slate-500 dark:text-slate-400">{label}</p>
          <p className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{value}</p>
        </div>
        <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${color}`}>
          <Icon className="w-6 h-6" />
        </div>
      </div>
    </div>
  );
}

// ─── Строка возврата ───────────────────────────────────────────────────────────

function ReturnRow({
  item,
  storeId,
}: {
  item: ReturnRequest;
  storeId: string;
}) {
  const [expanded, setExpanded] = useState(false);
  const [staffNote, setStaffNote] = useState(item.staffNote ?? "");
  const [refundAmount, setRefundAmount] = useState(String(item.refundAmount ?? ""));
  const [isPending, startTransition] = useTransition();
  const router = useRouter();

  const handleStatusUpdate = (status: "APPROVED" | "REJECTED" | "REFUNDED") => {
    startTransition(async () => {
      const result = await updateReturnStatus({
        returnId: item.id,
        status,
        staffNote: staffNote || undefined,
        refundAmount: refundAmount ? parseFloat(refundAmount) : undefined,
      });

      if (result.success) {
        toast.success(`Статус обновлён: ${STATUS_LABELS[status]}`);
        router.refresh();
      } else {
        toast.error(result.error ?? "Ошибка обновления статуса");
      }
    });
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
      {/* Заголовок строки */}
      <div className="p-4 flex items-center gap-4">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-3 mb-1">
            <span className="font-medium text-slate-900 dark:text-white truncate">
              {item.order.customerName}
            </span>
            <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${STATUS_COLORS[item.status]}`}>
              {STATUS_LABELS[item.status]}
            </span>
          </div>
          <div className="flex items-center gap-4 text-sm text-slate-500 dark:text-slate-400">
            <span>{item.order.customerEmail}</span>
            <span>·</span>
            <span>Заказ #{item.orderId.slice(-8).toUpperCase()}</span>
            <span>·</span>
            <span>{new Date(item.createdAt).toLocaleDateString("ru-RU")}</span>
          </div>
        </div>

        <div className="text-right shrink-0">
          <div className="font-semibold text-slate-900 dark:text-white">
            {item.refundAmount != null
              ? `₴${item.refundAmount.toLocaleString()}`
              : "—"}
          </div>
          <div className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
            {REFUND_METHOD_LABELS[item.refundMethod]}
          </div>
        </div>

        <button
          onClick={() => setExpanded(!expanded)}
          className="p-2 text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
        >
          {expanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
        </button>
      </div>

      {/* Развёрнутое содержимое */}
      {expanded && (
        <div className="border-t border-slate-200 dark:border-slate-700 p-4 space-y-4">
          {/* Причина возврата */}
          <div>
            <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1">
              Причина клиента
            </p>
            <p className="text-sm text-slate-700 dark:text-slate-300">{item.reason}</p>
          </div>

          {/* Товары в возврате */}
          {item.items.length > 0 && (
            <div>
              <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">
                Товары ({item.items.length})
              </p>
              <div className="space-y-1">
                {item.items.map((ri) => (
                  <div
                    key={ri.id}
                    className="flex items-center justify-between text-sm bg-slate-50 dark:bg-slate-700/50 rounded-lg px-3 py-2"
                  >
                    <span className="text-slate-600 dark:text-slate-300">
                      ID: {ri.orderItemId.slice(-8).toUpperCase()}
                    </span>
                    <span className="text-slate-500">× {ri.quantity}</span>
                    {ri.reason && (
                      <span className="text-slate-400 italic truncate max-w-[200px]">
                        {ri.reason}
                      </span>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Форма обработки (только для PENDING / APPROVED) */}
          {(item.status === "PENDING" || item.status === "APPROVED") && (
            <div className="border-t border-slate-200 dark:border-slate-700 pt-4 space-y-3">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
                    Сумма возврата (₴)
                  </label>
                  <input
                    type="number"
                    step="0.01"
                    value={refundAmount}
                    onChange={(e) => setRefundAmount(e.target.value)}
                    placeholder={String(item.order.totalPrice)}
                    className="w-full text-sm border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
                    Примечание персонала
                  </label>
                  <input
                    type="text"
                    value={staffNote}
                    onChange={(e) => setStaffNote(e.target.value)}
                    placeholder="Необязательно"
                    className="w-full text-sm border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>

              <div className="flex items-center gap-2">
                {item.status === "PENDING" && (
                  <button
                    onClick={() => handleStatusUpdate("APPROVED")}
                    disabled={isPending}
                    className="flex items-center gap-2 bg-green-600 hover:bg-green-700 disabled:opacity-50 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
                  >
                    <CheckCircle className="w-4 h-4" />
                    Одобрить
                  </button>
                )}
                {(item.status === "PENDING" || item.status === "APPROVED") && (
                  <button
                    onClick={() => handleStatusUpdate("REFUNDED")}
                    disabled={isPending}
                    className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
                  >
                    <CreditCard className="w-4 h-4" />
                    Подтвердить возврат
                  </button>
                )}
                {item.status === "PENDING" && (
                  <button
                    onClick={() => handleStatusUpdate("REJECTED")}
                    disabled={isPending}
                    className="flex items-center gap-2 bg-red-600 hover:bg-red-700 disabled:opacity-50 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
                  >
                    <XCircle className="w-4 h-4" />
                    Отклонить
                  </button>
                )}
              </div>
            </div>
          )}

          {/* Примечание персонала (для завершённых) */}
          {item.staffNote && item.status !== "PENDING" && (
            <div>
              <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1">
                Примечание персонала
              </p>
              <p className="text-sm text-slate-700 dark:text-slate-300 italic">{item.staffNote}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── Основной компонент ────────────────────────────────────────────────────────

const STATUS_FILTERS = [
  { value: undefined, label: "Все" },
  { value: "PENDING", label: "Ожидают" },
  { value: "APPROVED", label: "Одобренные" },
  { value: "REJECTED", label: "Отклонённые" },
  { value: "REFUNDED", label: "Возвращённые" },
];

export function ReturnsClient({
  returnsList,
  stats,
  storeId,
  currentStatus,
}: ReturnsClientProps) {
  const router = useRouter();

  const handleFilterChange = (status?: string) => {
    const url = status
      ? `/dashboard/${storeId}/returns?status=${status}`
      : `/dashboard/${storeId}/returns`;
    router.push(url);
  };

  return (
    <div className="space-y-6">
      {/* Заголовок */}
      <div>
        <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Возвраты и Рефанды</h1>
        <p className="text-slate-500 dark:text-slate-400 mt-1">
          Управление запросами на возврат товаров
        </p>
      </div>

      {/* Статистика */}
      <div className="grid grid-cols-2 md:grid-cols-4 xl:grid-cols-5 gap-4">
        <StatCard
          label="Ожидают"
          value={stats.pending}
          icon={Clock}
          color="bg-yellow-100 text-yellow-600 dark:bg-yellow-900/30 dark:text-yellow-400"
        />
        <StatCard
          label="Одобрены"
          value={stats.approved}
          icon={CheckCircle}
          color="bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400"
        />
        <StatCard
          label="Отклонены"
          value={stats.rejected}
          icon={XCircle}
          color="bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400"
        />
        <StatCard
          label="Возвращены"
          value={stats.refunded}
          icon={RotateCcw}
          color="bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400"
        />
        <StatCard
          label="Итого возвращено"
          value={`₴${stats.totalRefundAmount.toLocaleString()}`}
          icon={CreditCard}
          color="bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400"
        />
      </div>

      {/* Фильтры */}
      <div className="flex items-center gap-2 flex-wrap">
        <Filter className="w-4 h-4 text-slate-400" />
        {STATUS_FILTERS.map((filter) => (
          <button
            key={filter.value ?? "all"}
            onClick={() => handleFilterChange(filter.value)}
            className={`px-4 py-1.5 text-sm font-medium rounded-full transition-colors ${
              currentStatus === filter.value
                ? "bg-blue-600 text-white"
                : "bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-600"
            }`}
          >
            {filter.label}
          </button>
        ))}
      </div>

      {/* Список возвратов */}
      {returnsList.length === 0 ? (
        <div className="text-center py-16 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
          <RotateCcw className="w-12 h-12 text-slate-300 dark:text-slate-600 mx-auto mb-3" />
          <p className="text-slate-500 dark:text-slate-400 font-medium">Нет запросов на возврат</p>
          <p className="text-slate-400 dark:text-slate-500 text-sm mt-1">
            {currentStatus
              ? `Нет возвратов со статусом "${STATUS_LABELS[currentStatus]}"`
              : "Когда клиенты подадут заявки, они появятся здесь"}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {returnsList.map((item) => (
            <ReturnRow key={item.id} item={item} storeId={storeId} />
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { provideQuote, updateRFQStatus } from "@/actions/rfq";
import { toast } from "sonner";
import { RFQStatus } from "@prisma/client";
import { FileText, Check, X, Send } from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface RFQClientProps {
  storeId: string;
  initialData: any[]; // В идеале типизировать через Prisma.RFQGetPayload
}

const statusMap: Record<RFQStatus, { label: string, color: string }> = {
  PENDING: { label: "Ожидает", color: "bg-yellow-100 text-yellow-800" },
  QUOTED: { label: "КП отправлено", color: "bg-blue-100 text-blue-800" },
  ACCEPTED: { label: "Принято", color: "bg-green-100 text-green-800" },
  REJECTED: { label: "Отклонено", color: "bg-red-100 text-red-800" },
};

export function RFQClient({ storeId, initialData }: RFQClientProps) {
  const router = useRouter();
  const [rfqs, setRfqs] = useState(initialData);
  const [replyingTo, setReplyingTo] = useState<string | null>(null);
  const [quoteAmount, setQuoteAmount] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleProvideQuote = async (rfqId: string) => {
    const amount = parseFloat(quoteAmount);
    if (isNaN(amount) || amount < 0) {
      toast.error("Введите корректную сумму");
      return;
    }

    setIsSubmitting(true);
    try {
      const result = await provideQuote({ rfqId, totalAmount: amount });

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success(result.success);
      setReplyingTo(null);
      setQuoteAmount("");

      // Оптимистичное обновление
      setRfqs(prev => prev.map(r => 
        r.id === rfqId ? { ...r, status: RFQStatus.QUOTED, totalAmount: amount } : r
      ));

      router.refresh();
    } catch (error) {
      toast.error("Произошла ошибка");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleUpdateStatus = async (rfqId: string, status: RFQStatus) => {
    setIsSubmitting(true);
    try {
      const result = await updateRFQStatus({ rfqId, status });

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success(result.success);

      // Оптимистичное обновление
      setRfqs(prev => prev.map(r => 
        r.id === rfqId ? { ...r, status } : r
      ));

      router.refresh();
    } catch (error) {
      toast.error("Произошла ошибка");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl border shadow-sm overflow-hidden overflow-x-auto">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">ID Запроса</th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Клиент</th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Товары</th>
              <th className="px-6 py-4 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider">Статус</th>
              <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Предложенная цена</th>
              <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Действия</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {rfqs.map((rfq) => (
              <tr key={rfq.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center">
                    <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center mr-3">
                      <FileText className="h-4 w-4 text-blue-600" />
                    </div>
                    <div>
                      <div className="text-sm font-medium text-slate-900">
                        {rfq.id.substring(0, 8).toUpperCase()}
                      </div>
                      <div className="text-xs text-slate-500">
                        {new Date(rfq.createdAt).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="text-sm text-slate-900">{rfq.user?.name || "Без имени"}</div>
                  <div className="text-sm text-slate-500">{rfq.user?.email || "Аноним"}</div>
                </td>
                <td className="px-6 py-4">
                  <div className="text-sm text-slate-900">{rfq.items.length} поз.</div>
                  <div className="text-xs text-slate-500 truncate max-w-[200px]">
                    {rfq.items.map((i: any) => `${i.product?.name} (${i.quantity}шт)`).join(", ")}
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-center">
                  <Badge className={statusMap[rfq.status as RFQStatus].color} variant="outline">
                    {statusMap[rfq.status as RFQStatus].label}
                  </Badge>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  {rfq.totalAmount !== null ? `$${rfq.totalAmount.toFixed(2)}` : "—"}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  {replyingTo === rfq.id ? (
                    <div className="flex items-center justify-end gap-2">
                      <input 
                        type="number" 
                        placeholder="Сумма" 
                        value={quoteAmount}
                        onChange={(e) => setQuoteAmount(e.target.value)}
                        className="w-24 px-2 py-1 text-sm border rounded-md"
                        autoFocus
                      />
                      <Button size="sm" onClick={() => handleProvideQuote(rfq.id)} disabled={isSubmitting}>
                        <Check className="w-4 h-4" />
                      </Button>
                      <Button size="sm" variant="ghost" onClick={() => setReplyingTo(null)}>
                        <X className="w-4 h-4" />
                      </Button>
                    </div>
                  ) : (
                    <div className="flex justify-end gap-2">
                      {rfq.status === 'PENDING' && (
                        <>
                          <Button 
                            variant="outline" 
                            size="sm" 
                            onClick={() => {
                              setReplyingTo(rfq.id);
                              // Автоматически подставляем примерную сумму
                              const roughTotal = rfq.items.reduce((acc: number, item: any) => acc + (item.product?.price || 0) * item.quantity, 0);
                              setQuoteAmount(roughTotal.toString());
                            }}
                          >
                            <Send className="w-4 h-4 mr-1.5" />
                            Ответить
                          </Button>
                          <Button 
                            variant="ghost" 
                            size="sm" 
                            className="text-red-600 hover:text-red-900 hover:bg-red-50"
                            onClick={() => handleUpdateStatus(rfq.id, 'REJECTED')}
                            disabled={isSubmitting}
                          >
                            Отклонить
                          </Button>
                        </>
                      )}
                      {rfq.status === 'QUOTED' && (
                         <Button 
                          variant="ghost" 
                          size="sm" 
                          className="text-green-600 hover:text-green-900 hover:bg-green-50"
                          onClick={() => handleUpdateStatus(rfq.id, 'ACCEPTED')}
                          disabled={isSubmitting}
                        >
                          Принять заказ
                        </Button>
                      )}
                    </div>
                  )}
                </td>
              </tr>
            ))}
            {rfqs.length === 0 && (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center">
                  <FileText className="mx-auto h-12 w-12 text-slate-300 mb-3" />
                  <h3 className="text-sm font-medium text-slate-900">Нет запросов</h3>
                  <p className="mt-1 text-sm text-slate-500">
                    Здесь будут появляться запросы коммерческих предложений от клиентов.
                  </p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { createFeed, deleteFeed, toggleFeedActive } from "@/actions/feed";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Copy, Plus, Trash, Power, PowerOff } from "lucide-react";

export function FeedsClient({ feeds, storeId }: { feeds: any[]; storeId: string }) {
  const router = useRouter();
  const [isCreating, setIsCreating] = useState(false);
  const [formData, setFormData] = useState({ name: "", format: "YML" });
  const [loading, setLoading] = useState(false);

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const res = await createFeed(storeId, formData);
    if (res.error) {
      toast.error(res.error);
    } else {
      toast.success("Фид создан");
      setIsCreating(false);
      setFormData({ name: "", format: "YML" });
    }
    setLoading(false);
  };

  const copyLink = (slug: string) => {
    const url = `${window.location.origin}/api/feeds/${slug}`;
    navigator.clipboard.writeText(url);
    toast.success("Ссылка скопирована");
  };

  const onToggle = async (feedId: string, current: boolean) => {
    const res = await toggleFeedActive(feedId, storeId, !current);
    if (res.error) toast.error(res.error);
    else toast.success(res.success || "Статус изменен");
  };

  const onDelete = async (feedId: string) => {
    if (!confirm("Удалить этот фид?")) return;
    const res = await deleteFeed(feedId, storeId);
    if (res.error) toast.error(res.error);
    else toast.success("Удалено");
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold tracking-tight text-slate-100">Экспорт (Feeds)</h2>
          <p className="text-slate-400">Управляйте фидами товаров для выгрузки на другие площадки.</p>
        </div>
        <Button onClick={() => setIsCreating(!isCreating)} variant={isCreating ? "outline" : "default"}>
          {isCreating ? "Отмена" : <><Plus className="mr-2 h-4 w-4" /> Создать фид</>}
        </Button>
      </div>

      {isCreating && (
        <form onSubmit={onSubmit} className="bg-slate-900 border border-slate-800 p-6 rounded-xl space-y-4">
          <div className="space-y-2">
            <Label>Название фида</Label>
            <Input 
              value={formData.name} 
              onChange={(e) => setFormData({...formData, name: e.target.value})} 
              placeholder="Мой фид для Rozetka" 
              required
            />
          </div>
          <div className="space-y-2">
            <Label>Формат</Label>
            <Select value={formData.format} onValueChange={(v) => setFormData({...formData, format: v})}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="YML">YML (Prom.ua, Rozetka)</SelectItem>
                <SelectItem value="GOOGLE_XML">Google Shopping XML</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <Button type="submit" disabled={loading}>{loading ? "Создание..." : "Сохранить"}</Button>
        </form>
      )}

      <div className="rounded-md border border-slate-800">
        <Table>
          <TableHeader>
            <TableRow className="border-slate-800 hover:bg-slate-800/50">
              <TableHead className="text-slate-400">Название</TableHead>
              <TableHead className="text-slate-400">Формат</TableHead>
              <TableHead className="text-slate-400">Статус</TableHead>
              <TableHead className="text-slate-400">Ссылка</TableHead>
              <TableHead className="text-right text-slate-400">Действия</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {feeds.length === 0 ? (
              <TableRow className="border-slate-800">
                <TableCell colSpan={5} className="text-center text-slate-500 py-8">
                  Нет созданных фидов
                </TableCell>
              </TableRow>
            ) : (
              feeds.map((feed) => (
                <TableRow key={feed.id} className="border-slate-800 hover:bg-slate-800/50">
                  <TableCell className="font-medium text-slate-200">{feed.name}</TableCell>
                  <TableCell className="text-slate-300">
                    <Badge variant="outline" className="border-slate-700 bg-slate-800 text-slate-300">
                      {feed.format}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    {feed.isActive ? (
                      <Badge className="bg-emerald-500/10 text-emerald-500 border-emerald-500/20">Активен</Badge>
                    ) : (
                      <Badge className="bg-slate-500/10 text-slate-500 border-slate-500/20">Отключён</Badge>
                    )}
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <code className="bg-slate-900 px-2 py-1 rounded text-xs text-slate-400 truncate max-w-[200px]">
                        /api/feeds/{feed.urlSlug}
                      </code>
                      <Button variant="ghost" size="icon" onClick={() => copyLink(feed.urlSlug)} className="h-8 w-8 text-slate-400 hover:text-white">
                        <Copy className="h-4 w-4" />
                      </Button>
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    <Button 
                      variant="ghost" 
                      size="icon" 
                      onClick={() => onToggle(feed.id, feed.isActive)}
                      className={feed.isActive ? "text-amber-500 hover:text-amber-400" : "text-emerald-500 hover:text-emerald-400"}
                      title={feed.isActive ? "Отключить" : "Включить"}
                    >
                      {feed.isActive ? <PowerOff className="h-4 w-4" /> : <Power className="h-4 w-4" />}
                    </Button>
                    <Button 
                      variant="ghost" 
                      size="icon" 
                      onClick={() => onDelete(feed.id)}
                      className="text-red-500 hover:text-red-400 hover:bg-red-500/10"
                    >
                      <Trash className="h-4 w-4" />
                    </Button>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { toast } from "sonner";
import { useRouter } from "next/navigation";
import { saveIntegration } from "./actions";

interface IntegrationData {
  id?: string;
  providerName: string;
  apiKey: string;
  isActive: boolean;
  extraData: Record<string, any> | null;
}

interface IntegrationClientProps {
  initialData: IntegrationData[];
  storeId: string;
  availableProviders: string[];
}

export const IntegrationClient = ({ initialData, storeId, availableProviders }: IntegrationClientProps) => {
  const [integrations, setIntegrations] = useState<IntegrationData[]>(initialData);
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleSave = async (data: IntegrationData) => {
    setLoading(true);
    try {
      const response = await saveIntegration(storeId, data);
      if (response.success) {
        toast.success("Интеграция сохранена");
        router.refresh();
      } else {
        toast.error(response.error || "Ошибка сохранения");
      }
    } catch (error) {
      toast.error("Что-то пошло не так");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-4">
       {/* UI for displaying and adding integrations */}
       <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
         {availableProviders.map(provider => {
           const existing = integrations.find(i => i.providerName === provider);
           return (
             <div key={provider} className="p-4 border rounded-lg shadow-sm">
               <h3 className="font-semibold text-lg mb-2">{provider}</h3>
               {existing ? (
                  <div className="space-y-2">
                    <p className="text-sm text-gray-500">
                      Статус: {existing.isActive ? "Активна" : "Отключена"}
                    </p>
                    <button 
                      className="px-4 py-2 bg-gray-100 rounded text-sm hover:bg-gray-200"
                      onClick={() => handleSave({ ...existing, isActive: !existing.isActive })}
                    >
                      {existing.isActive ? "Отключить" : "Включить"}
                    </button>
                    {/* Add more detailed edit UI here */}
                  </div>
               ) : (
                  <button 
                    className="px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700"
                    onClick={() => {
                      // Open modal or form to add
                      const mockData: IntegrationData = {
                        providerName: provider,
                        apiKey: "mock-key",
                        isActive: true,
                        extraData: provider === "OPENCART" ? { storeUrl: "https://example.com" } : {}
                      }
                      handleSave(mockData);
                    }}
                  >
                    Подключить
                  </button>
               )}
             </div>
           )
         })}
       </div>
    </div>
  );
};

"use client";

import { useState, useTransition } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { Role } from "@prisma/client";
import { ASSIGNABLE_ROLES, getRoleLabel } from "@/lib/auth/permissions";
import { inviteTeamMember, removeTeamMember, updateMemberRole } from "@/actions/team";
import { UserPlus, Trash2, UserCog, Mail, Shield } from "lucide-react";

interface TeamMember {
  id: string;
  role: Role;
  user: {
    id: string;
    name: string | null;
    email: string;
    image: string | null;
  };
}

interface TeamClientProps {
  storeId: string;
  members: TeamMember[];
}

const inviteSchema = z.object({
  email: z.string().email("Введите корректный email"),
  role: z.enum(["ADMIN", "MANAGER", "MARKETER", "SUPPORT", "SELLER"]),
});
type InviteInput = z.infer<typeof inviteSchema>;

export function TeamClient({ storeId, members: initialMembers }: TeamClientProps) {
  const [members, setMembers] = useState<TeamMember[]>(initialMembers);
  const [showInviteForm, setShowInviteForm] = useState(false);
  const [isPending, startTransition] = useTransition();

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<InviteInput>({
    resolver: zodResolver(inviteSchema),
    defaultValues: { role: "MANAGER" },
  });

  const onInvite = (data: InviteInput) => {
    startTransition(async () => {
      const result = await inviteTeamMember({
        email: data.email,
        role: data.role as Role,
        storeId,
      });
      if (result.error) {
        toast.error(result.error);
      } else {
        toast.success(result.success);
        reset();
        setShowInviteForm(false);
      }
    });
  };

  const handleRemove = (memberId: string, memberName: string | null) => {
    if (!confirm(`Удалить ${memberName ?? "участника"} из команды?`)) return;
    startTransition(async () => {
      const result = await removeTeamMember(memberId, storeId);
      if (result.error) {
        toast.error(result.error);
      } else {
        toast.success(result.success);
        setMembers((prev) => prev.filter((m) => m.id !== memberId));
      }
    });
  };

  const handleRoleChange = (memberId: string, newRole: Role) => {
    startTransition(async () => {
      const result = await updateMemberRole(memberId, newRole, storeId);
      if (result.error) {
        toast.error(result.error);
      } else {
        toast.success(result.success);
        setMembers((prev) =>
          prev.map((m) => (m.id === memberId ? { ...m, role: newRole } : m))
        );
      }
    });
  };

  return (
    <div className="space-y-6">
      {/* Заголовок + кнопка */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2 text-sm text-gray-500">
          <Shield className="w-4 h-4" />
          <span>{members.length} участников в команде</span>
        </div>
        <button
          onClick={() => setShowInviteForm(!showInviteForm)}
          className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors"
        >
          <UserPlus className="w-4 h-4" />
          Пригласить участника
        </button>
      </div>

      {/* Форма приглашения */}
      {showInviteForm && (
        <div className="bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl p-6">
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
            <Mail className="w-5 h-5 text-blue-500" />
            Отправить приглашение
          </h3>
          <form onSubmit={handleSubmit(onInvite)} className="space-y-4">
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Email сотрудника
                </label>
                <input
                  type="email"
                  {...register("email")}
                  placeholder="employee@company.com"
                  className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 rounded-lg text-sm bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                {errors.email && (
                  <p className="text-red-500 text-xs mt-1">{errors.email.message}</p>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Роль
                </label>
                <select
                  {...register("role")}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 rounded-lg text-sm bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  {ASSIGNABLE_ROLES.map((role) => (
                    <option key={role} value={role}>
                      {getRoleLabel(role)}
                    </option>
                  ))}
                </select>
                {errors.role && (
                  <p className="text-red-500 text-xs mt-1">{errors.role.message}</p>
                )}
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button
                type="submit"
                disabled={isPending}
                className="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors"
              >
                {isPending ? "Отправка..." : "Отправить приглашение"}
              </button>
              <button
                type="button"
                onClick={() => {
                  setShowInviteForm(false);
                  reset();
                }}
                className="px-4 py-2 border border-gray-300 dark:border-slate-600 text-gray-700 dark:text-gray-300 text-sm font-medium rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
              >
                Отмена
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Таблица участников */}
      <div className="bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl overflow-hidden">
        {members.length === 0 ? (
          <div className="text-center py-12 text-gray-500 dark:text-gray-400">
            <UserCog className="w-12 h-12 mx-auto mb-3 text-gray-300" />
            <p className="text-lg font-medium">Команда пуста</p>
            <p className="text-sm mt-1">
              Пригласите сотрудников для совместной работы.
            </p>
          </div>
        ) : (
          <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200 dark:border-slate-700 bg-gray-50 dark:bg-slate-700/50">
                <th className="text-left px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  Участник
                </th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  Роль
                </th>
                <th className="px-6 py-3" />
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
              {members.map((member) => (
                <tr
                  key={member.id}
                  className="hover:bg-gray-50 dark:hover:bg-slate-700/30 transition-colors"
                >
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      {member.user.image ? (
                        <img
                          src={member.user.image}
                          alt={member.user.name ?? ""}
                          className="w-9 h-9 rounded-full object-cover"
                        />
                      ) : (
                        <div className="w-9 h-9 rounded-full bg-blue-100 dark:bg-blue-900 flex items-center justify-center text-blue-600 dark:text-blue-400 text-sm font-semibold">
                          {(member.user.name ?? member.user.email)[0].toUpperCase()}
                        </div>
                      )}
                      <div>
                        <p className="text-sm font-medium text-gray-900 dark:text-white">
                          {member.user.name ?? "—"}
                        </p>
                        <p className="text-xs text-gray-500 dark:text-gray-400">
                          {member.user.email}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <select
                      value={member.role}
                      onChange={(e) =>
                        handleRoleChange(member.id, e.target.value as Role)
                      }
                      disabled={isPending}
                      className="px-2 py-1 text-sm border border-gray-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-700 dark:text-gray-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      {ASSIGNABLE_ROLES.map((role) => (
                        <option key={role} value={role}>
                          {getRoleLabel(role)}
                        </option>
                      ))}
                    </select>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button
                      onClick={() =>
                        handleRemove(member.id, member.user.name)
                      }
                      disabled={isPending}
                      className="p-2 text-gray-400 hover:text-red-500 disabled:opacity-50 transition-colors rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20"
                      title="Удалить участника"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { ThemeConfig } from "@/lib/validations/store";
import { updateStoreTheme } from "@/actions/store";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";

interface ThemeSettingsClientProps {
  storeId: string;
  initialConfig: ThemeConfig;
}

export function ThemeSettingsClient({
  storeId,
  initialConfig,
}: ThemeSettingsClientProps) {
  const [isPending, setIsPending] = useState(false);
  const [config, setConfig] = useState<ThemeConfig>(initialConfig);

  const radiusMap = {
    none: "0",
    sm: "0.25rem",
    md: "0.5rem",
    lg: "1rem",
    full: "9999px",
  };

  const previewStyle = {
    "--preview-primary": config.primaryColor,
    "--preview-radius": radiusMap[config.borderRadius],
    fontFamily: config.fontFamily === "Inter" 
      ? "var(--font-geist-sans)" 
      : config.fontFamily,
  } as React.CSSProperties;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsPending(true);

    try {
      const result = await updateStoreTheme(storeId, config);

      if (result.error) {
        toast.error(result.error);
      } else {
        toast.success(result.success);
      }
    } catch (error) {
      toast.error("Произошла непредвиденная ошибка");
    } finally {
      setIsPending(false);
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
      <div>
        <form onSubmit={handleSubmit}>
          <Card>
            <CardHeader>
              <CardTitle>Настройки темы</CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">

              <div className="space-y-2">
                <Label htmlFor="primaryColor">Основной цвет (HEX)</Label>
                <div className="flex gap-2">
                  <Input
                    id="primaryColor"
                    type="color"
                    value={config.primaryColor}
                    onChange={(e) =>
                      setConfig({ ...config, primaryColor: e.target.value })
                    }
                    className="w-16 h-10 p-1 cursor-pointer"
                  />
                  <Input
                    type="text"
                    value={config.primaryColor}
                    onChange={(e) =>
                      setConfig({ ...config, primaryColor: e.target.value })
                    }
                    className="flex-1 uppercase"
                    pattern="^#[0-9A-Fa-f]{6}$"
                  />
                </div>
              </div>

              <div className="space-y-3">
                <Label>Скругление углов</Label>
                <RadioGroup
                  value={config.borderRadius}
                  onValueChange={(value: any) =>
                    setConfig({ ...config, borderRadius: value })
                  }
                  className="flex gap-4 flex-wrap"
                >
                  <div className="flex items-center space-x-2">
                    <RadioGroupItem value="none" id="r-none" />
                    <Label htmlFor="r-none">Нет</Label>
                  </div>
