                            {child.name}
                          </span>
                          {child.children && child.children.length > 0 && (
                            <div className="mt-2 space-y-1">
                              {child.children.map((subChild) => (
                                <span 
                                  key={subChild.id}
                                  className="text-gray-500 text-sm hover:text-blue-600 transition-colors cursor-pointer block py-0.5"
                                >
                                  {subChild.name}
                                </span>
                              ))}
                            </div>
                          )}
