            case "Button":
              return <ButtonBlock key={block.id} block={block as any} />;

            case "Divider":
              return <DividerBlock key={block.id} />;

            case "CountdownTimer":
              return <CountdownTimerBlock key={block.id} block={block as any} />;

            case "NewsletterForm":
              return <NewsletterFormBlock key={block.id} block={block as any} />;

            case "Accordion":
              return (
